    // Hits found
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #81c784;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Hits Found</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $results['total_hits'] . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Subject sequences</div>';
    $html .= '</div>';

    // Best hit info
    $best_hit = $results['hits'][0];
    $best_hsp = $best_hit['hsps'][0];
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ffa726;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Best E-value</div>';
    $evalue_display = sprintf('%.2e', $best_hit['best_evalue']);
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $evalue_display . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Top hit</div>';
    $html .= '</div>';

    // Best identity
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ef5350;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Best Identity</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $best_hsp['percent_identity'] . '%</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">' . $best_hsp['identities'] . '/' . $best_hsp['alignment_length'] . ' bp/aa</div>';
    $html .= '</div>';

    // Total HSPs
    $total_hsps = 0;
    foreach ($results['hits'] as $hit) {
        $total_hsps += $hit['num_hsps'];
    }
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #ab47bc;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Total HSPs</div>';
    $html .= '<div style="font-size: 24px; font-weight: bold;">' . $total_hsps . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Alignments</div>';
    $html .= '</div>';

    // Program
    $html .= '<div style="background: rgba(255,255,255,0.15); padding: 15px; border-radius: 6px; border-left: 4px solid #29b6f6;">';
    $html .= '<div style="font-size: 12px; opacity: 0.9; margin-bottom: 5px;">Program</div>';
    $html .= '<div style="font-size: 18px; font-weight: bold;">' . strtoupper(htmlspecialchars($blast_program)) . '</div>';
    $html .= '<div style="font-size: 11px; opacity: 0.8; margin-top: 5px;">Sequence search</div>';
    $html .= '</div>';

    $html .= '</div>'; // End grid

    $html .= '</div>'; // End container

    return $html;
}

function buildBlastHitLinkouts($hit, $context) {
    if (empty($context)) return '';

    $site           = $context['site']           ?? '';
    $organism       = $context['organism']       ?? '';
    $assembly       = $context['assembly']       ?? '';
    $is_genome_db   = $context['is_genome_db']   ?? false;
    $has_sqlite     = $context['has_sqlite']     ?? false;
    $has_jbrowse    = $context['has_jbrowse']    ?? false;
    $coords         = $context['coords']         ?? [];
    $linkout_config = $context['linkout_config'] ?? [];
    $db_seq_type    = $context['db_seq_type']    ?? '';

    $hit_id = cleanBlastHitId($hit['id'] ?? '');
    // Strip FASTA export type suffixes (:cds, :pep, etc.) — feature_coords.tsv uses bare IDs
    $hit_id = preg_replace('/:[a-z]+$/', '', $hit_id);
    // NCBI extracted CDS format: {chr}_cds_{ProteinAccession}_{index} → extract accession
    if (preg_match('/_cds_([A-Z]{2}_?\d+\.\d+)_\d+$/', $hit_id, $m)) {
        $hit_id = $m[1];
    }

    $html = '';

    $gene_page_label  = htmlspecialchars($linkout_config['gene_page_label']       ?? 'Gene Page');
    $jbrowse_label    = htmlspecialchars($linkout_config['jbrowse_label']         ?? 'Genome Browser');
    $hsp_min_score    = (float)($linkout_config['jbrowse_hsp_min_score']          ?? 0);
    $hsp_max_span     = (int)($linkout_config['jbrowse_hsp_max_span']             ?? 500000);
    $hsp_max_link     = max(1, (int)($linkout_config['jbrowse_hsp_max_link']      ?? 10));
    $jb2_assembly_id  = $organism . '_' . $assembly; // JBrowse2 assembly name format

    if ($is_genome_db) {
        // Genome BLAST: hit subject is a chromosome/scaffold; HSP coords are genomic.
        // Build a sessionTracks payload so JBrowse2 shows each HSP as a colored block.
        // Connect HSPs only if total span <= hsp_max_span AND score >= hsp_min_score.
        if (($linkout_config['jbrowse'] ?? false) && $has_jbrowse && !empty($hit['hsps'])) {
            // For genome BLAST, refName is the sequence ID (Hit_id), not the description (Hit_def)
            $subject    = $hit_id;
            $total_hsps = count($hit['hsps']);

            // Sort by score descending, keep top $hsp_max_link
            $hsps_sorted = $hit['hsps'];
            usort($hsps_sorted, fn($a, $b) => ($b['bit_score'] ?? 0) <=> ($a['bit_score'] ?? 0));
            $hsps_to_use = array_slice($hsps_sorted, 0, $hsp_max_link);
            $dropped     = $total_hsps - count($hsps_to_use);

            $all_s = array_map(fn($h) => min((int)$h['hit_from'], (int)$h['hit_to']) - 1, $hsps_to_use);
            $all_e = array_map(fn($h) => max((int)$h['hit_from'], (int)$h['hit_to']), $hsps_to_use);
            $parent_start = min($all_s);
            $parent_end   = max($all_e);
            $connect      = (($parent_end - $parent_start) <= $hsp_max_span);

            $subfeats   = [];
            $standalone = [];
            foreach ($hsps_to_use as $i => $hsp) {
                $s     = min((int)$hsp['hit_from'], (int)$hsp['hit_to']) - 1;
                $e     = max((int)$hsp['hit_from'], (int)$hsp['hit_to']);
                $score = (float)($hsp['bit_score'] ?? 0);
                $feat  = [
                    'uniqueId' => $hit_id . '_hsp_' . $i,
                    'refName'  => $subject,
                    'start'    => $s,
                    'end'      => $e,
                    'score'    => (int)$score,
                    'name'     => 'HSP ' . ($i + 1) . ' (evalue=' . sprintf('%.2e', $hsp['evalue'] ?? 0) . ')',
                    'type'     => 'match_part',
                ];
                if ($connect && $score >= $hsp_min_score) {
                    $subfeats[] = $feat;
                } else {
                    if (!$connect) $feat['name'] .= ' — span too large';
                    elseif ($score < $hsp_min_score) $feat['name'] .= ' — below score threshold';
                    $standalone[] = $feat;
                }
            }

            $track_id   = 'blast_' . substr(md5($hit_id), 0, 10);
            $track_name = 'BLAST: ' . $hit_id;
            if ($dropped > 0) {
                $track_name .= ' (top ' . count($hsps_to_use) . '/' . $total_hsps . ' HSPs by score)';
            }

            $features = [];
            if (!empty($subfeats)) {
                $features[] = [
                    'uniqueId'    => $hit_id . '_match',
                    'refName'     => $subject,
                    'start'       => $parent_start,
                    'end'         => $parent_end,
                    'name'        => $hit_id,
                    'type'        => 'match',
                    'subfeatures' => $subfeats,
                ];
            }
            foreach ($standalone as $sf) {
                $features[] = $sf;
            }

            $session_tracks = [[
                'type'          => 'FeatureTrack',
                'trackId'       => $track_id,
                'name'          => $track_name,
                'assemblyNames' => [$jb2_assembly_id],
                'adapter'       => ['type' => 'FromConfigAdapter', 'features' => $features],
            ]];

            $loc = $subject . ':' . ($parent_start + 1) . '-' . $parent_end;
            $url = "/$site/jbrowse2.php?organism=" . urlencode($organism)
                 . '&assembly='      . urlencode($assembly)
                 . '&loc='           . urlencode($loc)
                 . '&sessionTracks=' . urlencode(json_encode($session_tracks))
                 . '&sessionTrackId='. urlencode($track_id);

            $hsp_count = count($hsps_to_use);
            if ($dropped > 0) {
                $btn_label = 'View hit with ' . $hsp_count . ' of ' . $total_hsps . ' HSPs in browser';
            } else {
                $btn_label = 'View hit with ' . $hsp_count . ' ' . ($hsp_count === 1 ? 'HSP' : 'HSPs') . ' in browser';
            }
            $html .= '<a href="' . htmlspecialchars($url) . '" target="_blank" '
                   . 'class="btn btn-sm btn-outline-success me-1">'
                   . $btn_label . '</a>';
        }
    } else {
        // Feature BLAST (mRNA / CDS / protein): hit ID is a feature uniquename
        $entry   = $coords[$hit_id] ?? null;
        $gene_id = $entry ? $entry['gene_id'] : $hit_id;

        if (($linkout_config['gene_page'] ?? false) && $has_sqlite) {
            $url  = "/$site/tools/parent.php?uniquename=" . urlencode($gene_id)
                  . '&organism=' . urlencode($organism)
                  . '&assembly=' . urlencode($assembly);
            $html .= '<a href="' . htmlspecialchars($url) . '" target="_blank" '
                   . 'class="btn btn-sm btn-outline-primary me-1">'
                   . $gene_page_label . '</a>';
        }

        if (($linkout_config['jbrowse'] ?? false) && $has_jbrowse && $entry) {
            $loc  = $entry['chr'] . ':' . $entry['start'] . '-' . $entry['end'];
            $url  = "/$site/jbrowse2.php?organism=" . urlencode($organism)
                  . '&assembly=' . urlencode($assembly)
                  . '&loc=' . urlencode($loc);
            $html .= '<a href="' . htmlspecialchars($url) . '" target="_blank" '
                   . 'class="btn btn-sm btn-outline-success me-1">'
                   . $jbrowse_label . '</a>';
        }
    }

    // Global external linkouts — apply to all DB types
    foreach (($linkout_config['external'] ?? []) as $ext) {
        $template = $ext['url_template'] ?? '';
        $label    = htmlspecialchars($ext['label'] ?? 'Link');
        if (empty($template)) continue;
        $url = str_replace(
            ['{fasta_id}', '{organism}', '{assembly}'],
            [urlencode($hit_id), urlencode($organism), urlencode($assembly)],
            $template
        );
        $html .= '<a href="' . htmlspecialchars($url) . '" target="_blank" '
               . 'class="btn btn-sm btn-outline-secondary me-1">'
               . '<i class="fa fa-external-link-alt"></i> ' . $label . '</a>';
    }

    // Per-DB external linkouts — only for the active organism|assembly|seq_type
    if ($db_seq_type !== '') {
        $per_db_key = $organism . '|' . $assembly . '|' . $db_seq_type;
        foreach (($linkout_config['per_db_external'][$per_db_key] ?? []) as $ext) {
            $template = $ext['url_template'] ?? '';
            $label    = htmlspecialchars($ext['label'] ?? 'Link');
            if (empty($template)) continue;
            $url = str_replace(
                ['{fasta_id}', '{organism}', '{assembly}'],
                [urlencode($hit_id), urlencode($organism), urlencode($assembly)],
                $template
            );
            $html .= '<a href="' . htmlspecialchars($url) . '" target="_blank" '
                   . 'class="btn btn-sm btn-outline-info me-1">'
                   . '<i class="fa fa-external-link-alt"></i> ' . $label . '</a>';
        }
    }

    return $html;
}

