    return $public_groups;
}

function getAccessibleOrganismsInGroup($group_name, $group_data) {
    $group_organisms = [];

    // Find all organisms/assemblies in this group
    foreach ($group_data as $data) {
        if (in_array($group_name, $data['groups'])) {
            $organism = $data['organism'];
            $assembly = $data['assembly'];

            if (!isset($group_organisms[$organism])) {
                $group_organisms[$organism] = [];
            }
            $group_organisms[$organism][] = $assembly;
        }
    }

    // Filter: only keep organisms with at least one accessible assembly
    $accessible_organisms = [];
    foreach ($group_organisms as $organism => $assemblies) {
        $has_accessible_assembly = false;

        foreach ($assemblies as $assembly) {
            // Check if user has access to this specific assembly
            if (has_assembly_access($organism, $assembly)) {
                $has_accessible_assembly = true;
                break;
            }
        }

        if ($has_accessible_assembly) {
            $accessible_organisms[$organism] = $assemblies;
        }
    }

    // Sort organisms alphabetically
    ksort($accessible_organisms);

    return $accessible_organisms;
}

function getGroupsForOrganism($organism_name, $group_data = null) {
    if ($group_data === null) {
        $group_data = getGroupData();
    }

    $organism_groups = [];

    // Find all groups containing this organism
    foreach ($group_data as $data) {
        if ($data['organism'] === $organism_name) {
            foreach ($data['groups'] as $group) {
                if (!isset($organism_groups[$group])) {
                    $organism_groups[$group] = [
                        'count' => 0,
                        'link' => 'tools/groups.php?group=' . urlencode($group)
                    ];
                }
            }
        }
    }

    // Count accessible organisms in each group
    foreach ($organism_groups as $group => &$info) {
        $accessible_organisms = getAccessibleOrganismsInGroup($group, $group_data);
        $info['count'] = count($accessible_organisms);
    }

    // Sort by group name
    ksort($organism_groups);

    return $organism_groups;
}

function getOrganismsAtTaxonomyLevel($rank_name, $tree_node, $group_data) {
    if (empty($rank_name) || empty($tree_node) || empty($group_data)) {
        return [];
    }

    $organisms_at_level = [];

    // Find the rank in the tree and collect all organisms under it
    $findOrganisms = function($node) use ($rank_name, &$organisms_at_level, &$findOrganisms) {
        // Check if this is the target rank
        if ($node['name'] === $rank_name) {
            // Collect all organisms under this rank
            $collectOrganisms = function($n) use (&$collectOrganisms, &$organisms_at_level) {
                if (isset($n['organism'])) {
                    $organisms_at_level[$n['organism']] = true;
                }
                if (isset($n['children']) && is_array($n['children'])) {
                    foreach ($n['children'] as $child) {
                        $collectOrganisms($child);
                    }
                }
            };
            $collectOrganisms($node);
            return;
        }

        // Continue traversing
        if (isset($node['children']) && is_array($node['children'])) {
            foreach ($node['children'] as $child) {
                $findOrganisms($child);
            }
        }
    };

    $findOrganisms($tree_node);

    // Now filter by user access and get assemblies
    $accessible_organisms = [];
    foreach ($organisms_at_level as $organism => $dummy) {
        // Find all assemblies for this organism
        $organism_assemblies = [];
        foreach ($group_data as $data) {
            if ($data['organism'] === $organism) {
                $organism_assemblies[] = $data['assembly'];
            }
        }

        // Check if user has access to at least one assembly
        $has_accessible_assembly = false;
        foreach ($organism_assemblies as $assembly) {
            if (has_assembly_access($organism, $assembly)) {
                $has_accessible_assembly = true;
                break;
            }
        }

        if ($has_accessible_assembly) {
            $accessible_organisms[$organism] = $organism_assemblies;
        }
    }

    // Sort organisms alphabetically
    ksort($accessible_organisms);

    return $accessible_organisms;
}

function getAssemblyFastaFiles($organism_name, $assembly_name) {
    $config = ConfigManager::getInstance();
    $organism_data = $config->getPath('organism_data');
    $sequence_types = $config->getSequenceTypes();
    $fasta_files = [];
    $assembly_dir = "$organism_data/$organism_name/$assembly_name";

    if (!is_dir($assembly_dir)) {
        return $fasta_files;
    }

    // genome.fa stays at assembly level (not in a gene_set subdir)
    foreach ($sequence_types as $type => $seq_config) {
        if (strpos($seq_config['pattern'], 'genome') !== false) {
            if (file_exists("$assembly_dir/genome.fa")) {
                $fasta_files[$type] = [
                    'path'     => "$organism_name/$assembly_name/genome.fa",
                    'label'    => $seq_config['label'],
                    'color'    => $seq_config['color'],
                    'gene_set' => '',
                    'seq_type' => $type,
                ];
            }
            break;
        }
    }

    // protein/transcript/cds live in gene_set subdirs
    $gene_set_dirs = glob("$assembly_dir/*", GLOB_ONLYDIR) ?: [];
    $multi_gs = count($gene_set_dirs) > 1;
    foreach ($gene_set_dirs as $gs_dir) {
        $gene_set = basename($gs_dir);
        foreach ($sequence_types as $type => $seq_config) {
            if (strpos($seq_config['pattern'], 'genome') !== false) continue;
            $matches = glob("$gs_dir/" . $seq_config['pattern']);
            if (!empty($matches)) {
                $key = $type . '.' . $gene_set;
                $label = $seq_config['label'];
                if ($multi_gs) {
                    $label .= ' (' . $gene_set . ')';
                }
                $fasta_files[$key] = [
                    'path'     => "$organism_name/$assembly_name/$gene_set/" . basename($matches[0]),
                    'label'    => $label,
                    'color'    => $seq_config['color'],
                    'gene_set' => $gene_set,
                    'seq_type' => $type,
                ];
            }
        }
    }

    return $fasta_files;
}

function getIndexDisplayCards($group_data) {
    $cards_to_display = [];
    $all_cards = getAllGroupCards($group_data);

    if (get_access_level() === 'ADMIN' || get_access_level() === 'IP_IN_RANGE') {
        $cards_to_display = $all_cards;
    } elseif (is_logged_in()) {
        // Logged-in users see: public groups + any groups containing their permitted organisms
        $cards_to_display = getPublicGroupCards($group_data);

        $user_organisms = array_keys(get_user_access());
        $group_organisms = [];
        foreach ($group_data as $entry) {
            if (!in_array($entry['organism'], $user_organisms, true)) continue;
            foreach ($entry['groups'] as $group) {
                if (isset($cards_to_display[$group])) continue;
                if (!isset($group_organisms[$group])) $group_organisms[$group] = [];
                $group_organisms[$group][$entry['organism']] = true;
            }
        }
        foreach ($group_organisms as $group => $orgs) {
            $cards_to_display[$group] = [
                'title'          => $group,
                'text'           => "Explore $group Data",
                'link'           => 'tools/groups.php?group=' . urlencode($group),
                'organism_count' => count($orgs),
            ];
        }
    } else {
        // Visitors see only groups with public assemblies
        $cards_to_display = getPublicGroupCards($group_data);
    }

    return $cards_to_display;
}

function formatIndexOrganismName($organism) {
    $parts = explode('_', $organism);
    $formatted_name = ucfirst(strtolower($parts[0]));
    for ($i = 1; $i < count($parts); $i++) {
        $formatted_name .= ' ' . strtolower($parts[$i]);
    }
    return '<i>' . $formatted_name . '</i>';
}

function loadAllOrganismsMetadata($organism_data_dir) {
    $organisms = [];

    if (!is_dir($organism_data_dir)) {
        return $organisms;
    }

    $entries = scandir($organism_data_dir);
    foreach ($entries as $organism) {
        // Skip hidden directories and non-directories
        if ($organism[0] === '.' || !is_dir("$organism_data_dir/$organism")) {
            continue;
        }

        // Load organism.json using loadJsonFile (from functions_json.php)
        $organism_json_path = "$organism_data_dir/$organism/organism.json";
        $organism_info = loadJsonFile($organism_json_path);

        if (!$organism_info) {
            continue;
        }

        // Handle improperly wrapped JSON (extra outer braces)
        if (!isset($organism_info['genus']) && !isset($organism_info['common_name'])) {
            $keys = array_keys($organism_info);
            if (count($keys) > 0 && is_array($organism_info[$keys[0]]) && isset($organism_info[$keys[0]]['genus'])) {
                $organism_info = $organism_info[$keys[0]];
            }
        }

        // Store organism metadata keyed by organism name
        $organisms[$organism] = [
            'genus' => $organism_info['genus'] ?? '',
            'species' => $organism_info['species'] ?? '',
            'common_name' => $organism_info['common_name'] ?? '',
            'taxon_id' => $organism_info['taxon_id'] ?? '',
            'images' => $organism_info['images'] ?? [],
            'html_p' => $organism_info['html_p'] ?? []
        ];
    }

    return $organisms;
}

function getOrganismsWithAssemblies($organism_data_path) {
    if (!is_dir($organism_data_path)) {
        return [];
    }

    if (session_status() === PHP_SESSION_ACTIVE) {
        $cache_key = 'organisms_with_assemblies_cache';
        $dir_mtime = filemtime($organism_data_path);
        if (isset($_SESSION[$cache_key]) && $_SESSION[$cache_key]['mtime'] === $dir_mtime) {
            return $_SESSION[$cache_key]['data'];
        }
    }

    $orgs = [];
    foreach (scandir($organism_data_path) as $organism) {
        if ($organism[0] === '.' || !is_dir("$organism_data_path/$organism")) {
            continue;
        }
        $assemblies = [];
        $assemblyPath = "$organism_data_path/$organism";
        foreach (scandir($assemblyPath) as $file) {
            if ($file[0] === '.' || !is_dir("$assemblyPath/$file")) {
                continue;
            }
            $assemblies[] = $file;
        }
        $orgs[$organism] = $assemblies;
    }

    if (session_status() === PHP_SESSION_ACTIVE) {
        $_SESSION[$cache_key] = ['mtime' => $dir_mtime, 'data' => $orgs];
    }

    return $orgs;
}

function getAllExistingGroups($groups_data) {
    $all_groups = [];
    foreach ($groups_data as $data) {
        if (!empty($data['groups'])) {
            foreach ($data['groups'] as $group) {
                $all_groups[$group] = true;
            }
        }
    }
    $group_list = array_keys($all_groups);
    sort($group_list);
    return $group_list;
}

function syncGroupDescriptions($existing_groups, $descriptions_data) {
    $desc_map = [];
    foreach ($descriptions_data as $desc) {
        $desc_map[$desc['group_name']] = $desc;
    }

    $updated_descriptions = [];

    // Update existing groups to in_use = true
    foreach ($existing_groups as $group) {
        if (isset($desc_map[$group])) {
            $desc_map[$group]['in_use'] = true;
            $updated_descriptions[] = $desc_map[$group];
        } else {
            // New group - add with default structure
            $updated_descriptions[] = [
                'group_name' => $group,
                'images' => [
                    [
                        'file' => '',
                        'caption' => ''
                    ]
                ],
                'html_p' => [
                    [
                        'text' => '',
                        'style' => '',
                        'class' => ''
                    ]
                ],
                'in_use' => true
            ];
        }
        unset($desc_map[$group]);
    }

    // Mark any remaining groups (not in existing groups) as in_use = false
    foreach ($desc_map as $group_name => $desc) {
        $desc['in_use'] = false;
        $updated_descriptions[] = $desc;
    }

    return $updated_descriptions;
}

function getDetailedOrganismsInfo($organism_data_path, $sequence_types = [], $progress_callback = null) {
    $organisms_info = [];

    if (!is_dir($organism_data_path)) {
        return $organisms_info;
    }

    // Load all organisms' JSON metadata using consolidated function
    $organisms_metadata = loadAllOrganismsMetadata($organism_data_path);

    // Count organism directories for progress reporting
    $organisms = scandir($organism_data_path);
    $org_count = 0;
    $org_total = 0;
    if ($progress_callback) {
        foreach ($organisms as $o) {
            if ($o[0] !== '.' && is_dir("$organism_data_path/$o")) {
                $org_total++;
            }
        }
    }

    foreach ($organisms as $organism) {
        if ($organism[0] === '.' || !is_dir("$organism_data_path/$organism")) {
            continue;
        }

        $org_count++;
        if ($progress_callback) {
            $progress_callback($organism, $org_count, $org_total);
        }

        // Get organism.json info (already loaded from consolidated function)
        $organism_json = "$organism_data_path/$organism/organism.json";
        $json_validation = validateOrganismJson($organism_json);
        $info = $organisms_metadata[$organism] ?? [];

        // Get assemblies
        $assemblies = [];
        $assembly_path = "$organism_data_path/$organism";
        $files = scandir($assembly_path);
        foreach ($files as $file) {
            if ($file[0] === '.' || !is_dir("$assembly_path/$file")) {
                continue;
            }
            $assemblies[] = $file;
        }

        // Check for database file
        $db_file = null;
        if (file_exists("$organism_data_path/$organism/organism.sqlite")) {
            $db_file = "$organism_data_path/$organism/organism.sqlite";
        }

        $has_db = !is_null($db_file);

        // Validate database integrity if database exists
        $db_validation = null;
        $assembly_validation = null;
        $fasta_validation = null;
        if ($has_db) {
            $db_validation = validateDatabaseIntegrity($db_file);
            // Also validate assembly directories
            $assembly_validation = validateAssemblyDirectories($db_file, "$organism_data_path/$organism");
        }
        // Validate FASTA files in assembly directories
        $fasta_validation = validateAssemblyFastaFiles("$organism_data_path/$organism", $sequence_types);

        $organisms_info[$organism] = [
            'info' => $info,
            'assemblies' => $assemblies,
            'has_db' => $has_db,
            'db_file' => $db_file,
            'db_validation' => $db_validation,
            'assembly_validation' => $assembly_validation,
            'fasta_validation' => $fasta_validation,
            'json_validation' => $json_validation,
            'path' => "$organism_data_path/$organism"
        ];
    }

    return $organisms_info;
}

function getAssemblyGroups($organism, $assembly, $groups_data) {
    $assembly_groups = [];

    foreach ($groups_data as $data) {
        if (!empty($data['groups'])) {
            foreach ($data['groups'] as $group) {
                // Check if this organism and assembly match
                if ($data['organism'] === $organism && $data['assembly'] === $assembly) {
                    $assembly_groups[] = $group;
                }
            }
        }
    }

    return $assembly_groups;
}

function isAssemblyInTaxonomyTree($organism, $assembly, $tree_file) {
    if (!file_exists($tree_file)) {
        return false;
    }

    $tree_content = file_get_contents($tree_file);
    if (!$tree_content) {
        return false;
    }

    // Simply search for the organism name in the tree file
    return strpos($tree_content, '"organism": "' . $organism . '"') !== false;
}

function getOrganismOverallStatus($organism, $data, $groups_data, $taxonomy_tree_file, $sequence_types) {
    $checks = [
        'has_assemblies' => false,
        'has_fasta' => false,
        'has_blast_indexes' => false,
        'has_fai_index' => false,
        'has_database' => false,
        'database_valid' => false,
        'directories_match_db' => false,
        'assemblies_in_groups' => false,
        'in_taxonomy_tree' => false,
        'metadata_complete' => false,
    ];

    // 1. Does it have at least one assembly?
    $checks['has_assemblies'] = !empty($data['assemblies']);

    // 2. Is there at least one FASTA file in an assembly?
    if ($checks['has_assemblies'] && !empty($data['fasta_validation']['assemblies'])) {
        foreach ($data['fasta_validation']['assemblies'] as $asm_fasta) {
            if (!empty($asm_fasta['fasta_files'])) {
                foreach ($asm_fasta['fasta_files'] as $file_info) {
                    if ($file_info['found']) {
                        $checks['has_fasta'] = true;
                        break 2;
                    }
                }
            }
        }
    }

    // 3. Are BLAST indexes present for ALL FASTA files?
    // This check fails if there are FASTA files but any are missing BLAST indexes
    if ($checks['has_fasta']) {
        $all_have_indexes = true;
        $has_any_fasta = false;

        foreach ($data['assemblies'] as $assembly) {
            // Use pre-computed blast validation if available (from cache)
            $blast_validation = $data['blast_validation'][$assembly] ?? null;
            if (!$blast_validation) {
                $assembly_path = $data['path'] . '/' . $assembly;
                // Aggregate across gene_set subdirs
                $blast_validation = ['databases' => [], 'missing_count' => 0, 'total_count' => 0];
                foreach (glob($assembly_path . '/*', GLOB_ONLYDIR) ?: [] as $gs_dir) {
                    $bv = validateBlastIndexFiles($gs_dir, $sequence_types);
                    $blast_validation['databases']     = array_merge($blast_validation['databases'], $bv['databases']);
                    $blast_validation['missing_count'] += $bv['missing_count'];
                    $blast_validation['total_count']   += $bv['total_count'];
                }
            }

            if (!empty($blast_validation['databases'])) {
                foreach ($blast_validation['databases'] as $db) {
                    $has_any_fasta = true;
                    // If any FASTA file doesn't have indexes, fail the check
                    if (!$db['has_indexes']) {
                        $all_have_indexes = false;
                        break 2;
                    }
                }
            }
        }

        // Set to true only if we found FASTA files AND all have indexes
        $checks['has_blast_indexes'] = ($has_any_fasta && $all_have_indexes);
    }

    // 4. Does genome.fa have a .fai index for every assembly that has one?
    // Passes if no assembly has genome.fa (not applicable); fails if any genome.fa is missing .fai.
    if ($checks['has_assemblies']) {
        $any_genome_fa  = false;
        $all_have_fai   = true;
        foreach ($data['assemblies'] as $assembly) {
            $fai_info = $data['fai_validation'][$assembly] ?? null;
            if (!$fai_info) {
                $genome_fa = $data['path'] . '/' . $assembly . '/genome.fa';
                $fai_info  = [
                    'genome_fa_exists' => file_exists($genome_fa),
                    'fai_exists'       => file_exists($genome_fa . '.fai'),
                ];
            }
            if ($fai_info['genome_fa_exists']) {
                $any_genome_fa = true;
                if (!$fai_info['fai_exists']) {
                    $all_have_fai = false;
                    break;
                }
            }
        }
        $checks['has_fai_index'] = !$any_genome_fa || $all_have_fai;
    }

    // 5. Is there a database file?
    $checks['has_database'] = $data['has_db'];

    // 6. Is the database valid? (readable, correct schema, all tables present, no data issues)
    if ($checks['has_database'] && !empty($data['db_validation'])) {
        $checks['database_valid'] = $data['db_validation']['valid'] ?? $data['db_validation']['readable'];
    }

    // 7. Do assembly and gene_set directories on disk match the DB records?
    if ($checks['has_database'] && !empty($data['assembly_validation'])) {
        $checks['directories_match_db'] = $data['assembly_validation']['valid'] ?? false;
    } elseif ($checks['has_database'] && !empty($data['db_file']) && !empty($data['path'])) {
        $live = validateAssemblyDirectories($data['db_file'], $data['path']);
        $checks['directories_match_db'] = $live['valid'];
    }

    // 8. Is each assembly a member of at least one group?
    if ($checks['has_assemblies']) {
        $all_in_groups = true;
        foreach ($data['assemblies'] as $assembly) {
            $assembly_groups = getAssemblyGroups($organism, $assembly, $groups_data);
            if (empty($assembly_groups)) {
                $all_in_groups = false;
                break;
            }
        }
        $checks['assemblies_in_groups'] = $all_in_groups;
    }

    // 9. Is the organism found in the tree? (use pre-computed value from cache if available)
    $checks['in_taxonomy_tree'] = $data['in_taxonomy_tree'] ?? isAssemblyInTaxonomyTree($organism, '', $taxonomy_tree_file);

    // 10. Is metadata complete?
    if (!empty($data['json_validation'])) {
        $json_val = $data['json_validation'];
        $checks['metadata_complete'] = ($json_val['exists'] && $json_val['readable'] && $json_val['valid_json'] && $json_val['has_required_fields'] && $json_val['writable']);
    }

    // Calculate overall status
    $all_pass = array_reduce($checks, function($carry, $item) {
        return $carry && $item;
    }, true);

    $pass_count = count(array_filter($checks));
    $total_count = count($checks);

    return [
        'checks' => $checks,
        'all_pass' => $all_pass,
        'pass_count' => $pass_count,
        'total_count' => $total_count
    ];
}

function fetchOrganismInfoFromNCBI($genus, $species) {
    $result = [
        'taxon_id' => '',
        'common_name' => '',
        'scientific_name' => "$genus $species",
        'error' => ''
    ];

    if (empty($genus) || empty($species)) {
        $result['error'] = 'Genus and species are required';
        return $result;
    }

    // Search for the organism on NCBI
    $search_url = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?' . http_build_query([
        'db' => 'taxonomy',
        'term' => "$genus $species",
        'retmode' => 'json'
    ]);

    $response = moop_curl_get($search_url);

    if ($response === false) {
        $result['error'] = 'Failed to connect to NCBI';
        return $result;
    }

    $data = json_decode($response, true);

    if (empty($data['esearchresult']['idlist'])) {
        $result['error'] = 'Organism not found on NCBI';
        return $result;
    }

    $taxon_id = $data['esearchresult']['idlist'][0];
    $result['taxon_id'] = $taxon_id;

    // Fetch full details
    $fetch_url = 'https://eutils.ncbi.nlm.nih.gov/entrez/eutils/efetch.fcgi?' . http_build_query([
        'db' => 'taxonomy',
        'id' => $taxon_id,
        'retmode' => 'json'
    ]);

    $response = moop_curl_get($fetch_url);

    if ($response === false) {
        return $result;
    }

    $data = json_decode($response, true);

    if (!empty($data['result'][$taxon_id]['commonname'])) {
        $result['common_name'] = $data['result'][$taxon_id]['commonname'];
    }

    return $result;
}

function validateDatabaseFile($dbFile) {
    if (!file_exists($dbFile)) {
        return ['valid' => false, 'error' => 'Database file not found'];
    }

    if (!is_readable($dbFile)) {
        return ['valid' => false, 'error' => 'Database file not readable (permission denied)'];
    }

    try {
        $db = getDbConnection($dbFile);
        $db = null;
        return ['valid' => true, 'error' => ''];
    } catch (Exception $e) {
        return ['valid' => false, 'error' => $e->getMessage()];
    }
}

function validateDatabaseIntegrity($dbFile) {
    $result = [
        'valid' => false,
        'readable' => false,
        'database_valid' => false,
        'tables_present' => [],
        'tables_missing' => [],
        'row_counts' => [],
        'feature_counts' => [],
        'data_issues' => [],
        'errors' => []
    ];

    // Check if file exists and is readable
    if (!file_exists($dbFile)) {
        $result['errors'][] = 'Database file not found';
        return $result;
    }

    if (!is_readable($dbFile)) {
        $result['errors'][] = 'Database file not readable (permission denied)';
        return $result;
    }

    $result['readable'] = true;

    // Try to connect to database
    try {
        $dbh = getDbConnection($dbFile);
    } catch (PDOException $e) {
        $result['errors'][] = 'Invalid SQLite database: ' . $e->getMessage();
        return $result;
    }

    $result['database_valid'] = true;

    // Required tables based on schema
    $required_tables = [
        'organism',
        'genome',
        'gene_set',
        'feature',
        'annotation_source',
        'annotation',
        'feature_annotation'
    ];

    // Check which tables exist
    try {
        $stmt = $dbh->query("SELECT name FROM sqlite_master WHERE type='table'");
        $existing_tables = $stmt->fetchAll(PDO::FETCH_COLUMN);

        foreach ($required_tables as $table) {
            if (in_array($table, $existing_tables)) {
                $result['tables_present'][] = $table;
            } else {
                $result['tables_missing'][] = $table;
            }
        }
    } catch (PDOException $e) {
        $result['errors'][] = 'Cannot query tables: ' . $e->getMessage();
        $dbh = null;
        return $result;
    }

    // Check row counts and data quality
    try {
        foreach ($result['tables_present'] as $table) {
            $stmt = $dbh->query("SELECT COUNT(*) FROM $table");
            $count = $stmt->fetchColumn();
            $result['row_counts'][$table] = $count;
        }

        // Get counts by feature type
        if (in_array('feature', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT feature_type, COUNT(*) as count
                FROM feature
                GROUP BY feature_type
                ORDER BY feature_type
            ");
            $features = $stmt->fetchAll(PDO::FETCH_ASSOC);
            foreach ($features as $feature) {
                $result['feature_counts'][$feature['feature_type']] = $feature['count'];
            }
        }

        // Check for data quality issues

        // 1. Check for annotations without sources (orphaned)
        if (in_array('annotation', $result['tables_present']) && in_array('annotation_source', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT COUNT(*) FROM annotation a 
                LEFT JOIN annotation_source ans ON a.annotation_source_id = ans.annotation_source_id 
                WHERE ans.annotation_source_id IS NULL
            ");
            $orphaned_count = $stmt->fetchColumn();
            if ($orphaned_count > 0) {
                $result['data_issues'][] = "Orphaned annotations (no source): $orphaned_count";
            }
        }

        // 2. Check for incomplete annotations (missing accession or description)
        if (in_array('annotation', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT COUNT(*) FROM annotation 
                WHERE annotation_accession IS NULL OR annotation_accession = ''
            ");
            $missing_accession = $stmt->fetchColumn();
            if ($missing_accession > 0) {
                $result['data_issues'][] = "Annotations with missing accession: $missing_accession";
            }
        }

        // 3. Check for features without organisms
        if (in_array('feature', $result['tables_present']) && in_array('organism', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT COUNT(*) FROM feature f
                LEFT JOIN organism o ON f.organism_id = o.organism_id
                WHERE o.organism_id IS NULL
            ");
            $orphaned_features = $stmt->fetchColumn();
            if ($orphaned_features > 0) {
                $result['data_issues'][] = "Features without organism: $orphaned_features";
            }
        }

        // 4. Check for features with invalid gene_set_id
        if (in_array('feature', $result['tables_present']) && in_array('gene_set', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT COUNT(*) FROM feature f
                LEFT JOIN gene_set gs ON f.gene_set_id = gs.gene_set_id
                WHERE gs.gene_set_id IS NULL
            ");
            $orphaned_gs_features = $stmt->fetchColumn();
            if ($orphaned_gs_features > 0) {
                $result['data_issues'][] = "Features with invalid gene_set_id: $orphaned_gs_features";
            }
        }

        // 5. Check for gene_sets not linked to a genome
        if (in_array('gene_set', $result['tables_present']) && in_array('genome', $result['tables_present'])) {
            $stmt = $dbh->query("
                SELECT COUNT(*) FROM gene_set gs
                LEFT JOIN genome g ON gs.genome_id = g.genome_id
                WHERE g.genome_id IS NULL
            ");
            $orphaned_gene_sets = $stmt->fetchColumn();
            if ($orphaned_gene_sets > 0) {
                $result['data_issues'][] = "Gene sets with invalid genome_id: $orphaned_gene_sets";
            }
        }

    } catch (PDOException $e) {
        $result['errors'][] = 'Data quality check failed: ' . $e->getMessage();
    }

    $dbh = null;

    // Determine overall validity
    $result['valid'] = (
        $result['readable'] && 
        $result['database_valid'] && 
        empty($result['tables_missing']) && 
        empty($result['data_issues']) &&
        empty($result['errors'])
    );

    return $result;
}

function getDbConnection($dbFile) {
    // The single door for every SQLite connection in MOOP. Sets strict error mode so a
    // failed query THROWS instead of silently returning wrong/empty results (the class of
    // bug that made search hide its own failures), and registers the REGEXP helper.
    //
    // Throws PDOException on failure — it deliberately does NOT die(). Callers wrap this
    // in their own try/catch and decide what a failure means: surface a warning, report a
    // validation error, fall back to defaults, or let it bubble to a 500. die()-ing here
    // would stop validation probes and graceful-fallback callers from using this door.
    $dbh = new PDO("sqlite:" . $dbFile);
    $dbh->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    $dbh->sqliteCreateFunction('REGEXP', function($pattern, $text) {
        return preg_match('/' . $pattern . '/i', $text) ? 1 : 0;
    }, 2);
    return $dbh;
}

function fetchData($sql, $dbFile, $params = []) {
    try {
        $dbh = getDbConnection($dbFile);
        $stmt = $dbh->prepare($sql);
        $stmt->execute($params);
        $result = $stmt->fetchAll(PDO::FETCH_ASSOC);
        $dbh = null;
        return $result;
    } catch (PDOException $e) {
        die("Query failed: " . $e->getMessage());
    }
}

function buildLikeConditions($columns, $search, $quoted = false) {
    $conditions = [];
    $params = [];

    if ($quoted) {
        $searchConditions = [];
        foreach ($columns as $col) {
            $searchConditions[] = "$col LIKE ?";
            $params[] = "%" . $search . "%";
        }
        $conditions[] = "(" . implode(" OR ", $searchConditions) . ")";
    } else {
        $terms = preg_split('/\s+/', trim($search));
        foreach ($terms as $term) {
            if (empty($term)) continue;
            $termConditions = [];
            foreach ($columns as $col) {
                $termConditions[] = "$col LIKE ?";
                $params[] = "%" . $term . "%";
            }
            $conditions[] = "(" . implode(" OR ", $termConditions) . ")";
        }
    }

    $sqlFragment = implode(" AND ", $conditions);
    return [$sqlFragment, $params];
}

function getAccessibleGenomeIds($organism_name, $accessible_assemblies, $db_path) {
    if (empty($accessible_assemblies)) {
        return [];
    }

    $placeholders = implode(',', array_fill(0, count($accessible_assemblies), '?'));
    $query = "SELECT DISTINCT genome_id FROM genome 
              WHERE genome_name IN ($placeholders) 
              OR genome_accession IN ($placeholders)";

    // Pass accessible_assemblies twice - once for names, once for accessions
    $params = array_merge($accessible_assemblies, $accessible_assemblies);
    $results = fetchData($query, $db_path, $params);

    return array_column($results, 'genome_id');
}

function loadOrganismInfo($organism_name, $organism_data_dir) {
    $organism_json_path = "$organism_data_dir/$organism_name/organism.json";
    $organism_info = loadJsonFile($organism_json_path);

    if (!$organism_info) {
        return null;
    }

    // Handle improperly wrapped JSON (extra outer braces)
    if (!isset($organism_info['genus']) && !isset($organism_info['common_name'])) {
        $keys = array_keys($organism_info);
        if (count($keys) > 0 && is_array($organism_info[$keys[0]]) && isset($organism_info[$keys[0]]['genus'])) {
            $organism_info = $organism_info[$keys[0]];
        }
    }

    // Validate required fields
    if (!isset($organism_info['common_name']) && !isset($organism_info['genus'])) {
        return null;
    }

    return $organism_info;
}

function getOrganismDatabase($organism_name, $organism_data_dir) {
    $db_path = "$organism_data_dir/$organism_name/organism.sqlite";

    if (!file_exists($db_path)) {
        return null;
    }

    return $db_path;
}

function verifyOrganismDatabase($organism_name, $organism_data_dir) {
    $db_path = "$organism_data_dir/$organism_name/organism.sqlite";

    if (!file_exists($db_path)) {
        header("HTTP/1.1 500 Internal Server Error");
        die("Error: Database not found for organism '$organism_name'. Please ensure the organism is properly configured.");
    }

    return $db_path;
}

function getOrganismAssemblies($organism_name, $organism_data_dir) {
    $db_path = getOrganismDatabase($organism_name, $organism_data_dir);

    if (empty($db_path)) {
        return [];
    }

    try {
        $dbh = getDbConnection($db_path);

        $stmt = $dbh->query("SELECT genome_accession FROM genome ORDER BY genome_name ASC");
        $genomes = $stmt->fetchAll(PDO::FETCH_COLUMN);

        // Filter by user access
        $accessible = [];
        foreach ($genomes as $assembly) {
            if (has_assembly_access($organism_name, $assembly)) {
                $accessible[] = $assembly;
            }
        }

        return $accessible;
    } catch (PDOException $e) {
        return [];
    }
}

function loadOrganismAndGetImagePath($organism_name, $images_path = 'moop/images', $absolute_images_path = '') {
    $config = ConfigManager::getInstance();
    $organism_data = $config->getPath('organism_data');

    $result = [
        'organism_info' => [],
        'image_path' => ''
    ];

    // Use consolidated loadOrganismInfo() instead of manual JSON loading
    $organism_info = loadOrganismInfo($organism_name, $organism_data);
    if ($organism_info) {
        $result['organism_info'] = $organism_info;
        $result['image_path'] = getOrganismImagePath($organism_info, $images_path, $absolute_images_path);
    }

    return $result;
}

function getOrganismImagePath($organism_info, $images_path = 'moop/images', $absolute_images_path = '') {
    // Validate input
    if (empty($organism_info) || !is_array($organism_info)) {
        logError('getOrganismImagePath received invalid organism_info', 'organism_image', [
            'organism_info_type' => gettype($organism_info),
            'organism_info_empty' => empty($organism_info)
        ]);
        return '';
    }

    // 1. Check for custom image first
    if (!empty($organism_info['images']) && is_array($organism_info['images'])) {
        return "/$images_path/" . htmlspecialchars($organism_info['images'][0]['file']);
    }

    $config = ConfigManager::getInstance();
    $site = $config->getString('site');
    if (empty($absolute_images_path)) {
        $absolute_images_path = $config->getPath('absolute_images_path');
    }

    // 2. Fall back to NCBI taxonomy image if taxon_id exists
    if (!empty($organism_info['taxon_id'])) {
        $ncbi_image_file = "$absolute_images_path/ncbi_taxonomy/" . $organism_info['taxon_id'] . '.jpg';
        if (file_exists($ncbi_image_file)) {
            return "/$site/images/ncbi_taxonomy/" . $organism_info['taxon_id'] . ".jpg";
        }
    }

    // 3. Fall back to Wikipedia image (check cache first, then fetch on demand)
    $scientific_name = trim(($organism_info['genus'] ?? '') . ' ' . ($organism_info['species'] ?? ''));
    if (!empty($scientific_name)) {
        $wikimedia_dir = "$absolute_images_path/wikimedia";
        $safe_name = basename($scientific_name);

        // Check for already-cached Wikipedia image (any extension, with or without underscores)
        $safe_name_underscore = str_replace(' ', '_', $safe_name);
        foreach ([$safe_name, $safe_name_underscore] as $name_variant) {
            foreach (['jpg', 'jpeg', 'png', 'gif', 'webp'] as $ext) {
                $cached_file = "$wikimedia_dir/$name_variant.$ext";
                if (file_exists($cached_file)) {
                    return "/$site/images/wikimedia/" . rawurlencode("$name_variant.$ext");
                }
            }
        }

        // Fetch from Wikipedia and cache locally; pass scientific name as second arg so it is tried first
        $common_name = $organism_info['common_name'] ?? '';
        $wiki_data = getWikipediaOrganismData($common_name, $scientific_name);
        if (!empty($wiki_data['image_url'])) {
            $url_path = parse_url($wiki_data['image_url'], PHP_URL_PATH);
            $ext = strtolower(pathinfo($url_path, PATHINFO_EXTENSION) ?: 'jpg');
            $cache_filename = "$safe_name.$ext";
            $result = downloadWikimediaImage($wiki_data['image_url'], $cache_filename, $wikimedia_dir);
            if ($result) {
                return $result;
            }
            // Download failed; return remote URL so the browser can still show the image
            return $wiki_data['image_url'];
        }
    }

    return '';
}

function getOrganismImageCaption($organism_info, $absolute_images_path = '') {
    $result = [
        'caption' => '',
        'link' => ''
    ];

    // Validate input
    if (empty($organism_info) || !is_array($organism_info)) {
        logError('getOrganismImageCaption received invalid organism_info', 'organism_image', [
            'organism_info_type' => gettype($organism_info),
            'organism_info_empty' => empty($organism_info)
        ]);
        return $result;
    }

    // Custom image caption
    if (!empty($organism_info['images']) && is_array($organism_info['images'])) {
        if (!empty($organism_info['images'][0]['caption'])) {
            $result['caption'] = $organism_info['images'][0]['caption'];
        }
        return $result;
    }

    if (empty($absolute_images_path)) {
        $config = ConfigManager::getInstance();
        $absolute_images_path = $config->getPath('absolute_images_path');
    }

    // NCBI taxonomy caption with link
    if (!empty($organism_info['taxon_id'])) {
        $ncbi_image_file = "$absolute_images_path/ncbi_taxonomy/" . $organism_info['taxon_id'] . '.jpg';
        if (file_exists($ncbi_image_file)) {
            $result['caption'] = 'Image from NCBI Taxonomy';
            $result['link'] = 'https://www.ncbi.nlm.nih.gov/datasets/taxonomy/' . htmlspecialchars($organism_info['taxon_id']);
            return $result;
        }
    }

    // Wikipedia image caption
    $scientific_name = trim(($organism_info['genus'] ?? '') . ' ' . ($organism_info['species'] ?? ''));
    if (!empty($scientific_name)) {
        $safe_name = basename($scientific_name);
        $wikimedia_dir = "$absolute_images_path/wikimedia";
        foreach (['jpg', 'jpeg', 'png', 'gif', 'webp'] as $ext) {
            if (file_exists("$wikimedia_dir/$safe_name.$ext")) {
                $result['caption'] = 'Image from Wikipedia';
                $result['link'] = 'https://en.wikipedia.org/wiki/' . str_replace(' ', '_', $scientific_name);
                return $result;
            }
        }
    }

    return $result;
}

function getOrganismImageWithCaption($organism_info, $images_path = 'moop/images', $absolute_images_path = '') {
    $image_path = getOrganismImagePath($organism_info, $images_path, $absolute_images_path);
    $image_info = getOrganismImageCaption($organism_info, $absolute_images_path);

    return [
        'image_path' => $image_path,
        'caption' => $image_info['caption'],
        'link' => $image_info['link']
    ];
}

function validateOrganismJson($json_path) {
    $validation = [
        'exists' => false,
        'readable' => false,
        'writable' => false,
        'valid_json' => false,
        'has_required_fields' => false,
        'required_fields' => ['genus', 'species', 'common_name', 'taxon_id'],
        'missing_fields' => [],
        'errors' => [],
        'owner' => null,
        'perms' => null,
        'web_user' => null,
        'web_group' => null
    ];

    if (!file_exists($json_path)) {
        $validation['errors'][] = 'organism.json file does not exist';
        return $validation;
    }

    $validation['exists'] = true;

    // Get file ownership and permissions
    if (@is_readable($json_path) || @file_exists($json_path)) {
        $perms = @fileperms($json_path);
        if ($perms !== false) {
            $validation['perms'] = substr(sprintf('%o', $perms), -3);
        }
        if (function_exists('posix_getpwuid')) {
            $owner = @posix_getpwuid(@fileowner($json_path));
            if ($owner !== false) {
                $validation['owner'] = $owner['name'] ?? 'unknown';
            }
        }
    }

    // Get web server user/group
    $webserver = getWebServerUser();
    $validation['web_user'] = $webserver['user'];
    $validation['web_group'] = $webserver['group'];

    if (!is_readable($json_path)) {
        $validation['errors'][] = 'organism.json file is not readable';
        return $validation;
    }

    $validation['readable'] = true;
    $validation['writable'] = is_writable($json_path);

    $content = file_get_contents($json_path);
    $json_data = json_decode($content, true);

    if ($json_data === null) {
        $validation['errors'][] = 'organism.json contains invalid JSON: ' . json_last_error_msg();
        return $validation;
    }

    $validation['valid_json'] = true;

    // Handle wrapped JSON (single-level wrapping)
    if (!isset($json_data['genus']) && !isset($json_data['common_name'])) {
        $keys = array_keys($json_data);
        if (count($keys) > 0 && is_array($json_data[$keys[0]])) {
            $json_data = $json_data[$keys[0]];
        }
    }

    // Check for required fields
    foreach ($validation['required_fields'] as $field) {
        if (!isset($json_data[$field]) || empty($json_data[$field])) {
            $validation['missing_fields'][] = $field;
        }
    }

    $validation['has_required_fields'] = empty($validation['missing_fields']);

    if (!$validation['has_required_fields']) {
        $validation['errors'][] = 'Missing required fields: ' . implode(', ', $validation['missing_fields']);
    }

    return $validation;
}

function setupOrganismDisplayContext($organism_name, $organism_data_dir, $check_access = true, $redirect_home = null) {
    if ($redirect_home === null) {
        $site = ConfigManager::getInstance()->getString('site');
        $redirect_home = "/$site/index.php";
    }

    // Validate organism parameter
    $organism_name = validateOrganismParam($organism_name, $redirect_home);

    // Load and validate organism info
    $organism_info = loadOrganismInfo($organism_name, $organism_data_dir);

    if (!$organism_info) {
        header("Location: $redirect_home");
        exit;
    }

    // Check access (unless it's public)
    if ($check_access) {
        $is_public = is_public_organism($organism_name);
        if (!$is_public) {
            require_access('COLLABORATOR', $organism_name);
        }
    }

    return [
        'name' => $organism_name,
        'info' => $organism_info
    ];
}

function fetch_organism_image($taxon_id, $organism_name = null, $absolute_images_path = null, $max_retries = 2) {
    if ($absolute_images_path === null) {
        $config = ConfigManager::getInstance();
        $absolute_images_path = $config->getPath('absolute_images_path');
    }

    $ncbi_dir = $absolute_images_path . '/ncbi_taxonomy';
    $image_path = $ncbi_dir . '/' . $taxon_id . '.jpg';

    // Check if image already cached
    if (file_exists($image_path)) {
        return 'images/ncbi_taxonomy/' . $taxon_id . '.jpg';
    }

    // Ensure directory exists
    if (!is_dir($ncbi_dir)) {
        @mkdir($ncbi_dir, 0755, true);
    }

    // Download from NCBI with retry logic
    $image_url  = "https://api.ncbi.nlm.nih.gov/datasets/v2/taxonomy/taxon/{$taxon_id}/image";
    $attempt    = 0;
    $image_data = false;

    while ($attempt < $max_retries && $image_data === false) {
        $ch = curl_init($image_url);
        curl_setopt_array($ch, [
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT        => 15,
            CURLOPT_USERAGENT      => 'MOOP/1.0',
        ]);
        $result      = curl_exec($ch);
        $err         = curl_errno($ch);
        $http        = curl_getinfo($ch, CURLINFO_HTTP_CODE);
        $content_type = curl_getinfo($ch, CURLINFO_CONTENT_TYPE);
        curl_close($ch);

        $is_image = $content_type && strpos($content_type, 'image/') === 0;
        if ($result !== false && !$err && $http === 200 && $is_image && strlen($result) >= 100) {
            $image_data = $result;
        } else {
            $attempt++;
            if ($attempt < $max_retries) {
                usleep(1000000);
            }
        }
    }

    if ($image_data === false) {
        return null;
    }

    // Save image
    if (file_put_contents($image_path, $image_data) !== false) {
        return 'images/ncbi_taxonomy/' . $taxon_id . '.jpg';
    }

    return null;
}

function generatePermissionAlert($file_path, $title = '', $problem = '', $file_type = 'file', $organism = '') {
    // Check current permissions
    $readable = is_readable($file_path);
    $writable = is_writable($file_path);

    // If everything is fine, return empty
    if ($readable && $writable) {
        return '';
    }

    // Get file/directory info
    $exists = file_exists($file_path);
    if (!$exists) {
        return '';
    }

    $is_dir = is_dir($file_path);
    $file_size = $is_dir ? 'directory' : filesize($file_path) . ' bytes';
    $owner_name = 'unknown';
    if (function_exists('posix_getpwuid')) {
        $owner = @posix_getpwuid(fileowner($file_path));
        if ($owner !== false) { $owner_name = $owner['name']; }
    } else {
        $stat_out = [];
        @exec("stat -c '%U' " . escapeshellarg($file_path) . " 2>/dev/null", $stat_out);
        if (!empty($stat_out[0]) && $stat_out[0] !== 'UNKNOWN') { $owner_name = $stat_out[0]; }
    }
    $perms = substr(sprintf('%o', fileperms($file_path)), -3);
    $webserver = getWebServerUser();
    $web_user = $webserver['user'];
    $web_group = $webserver['group'];

    // Determine if web server can fix permissions
    $can_fix = is_writable(dirname($file_path)) || is_writable($file_path);

    // Determine what's wrong
    $issue = '';
    if (!$readable && !$writable) {
        $issue = 'Cannot read or write';
    } elseif (!$readable) {
        $issue = 'Cannot read (permission denied)';
    } else {
        $issue = 'Cannot write (read-only)';
    }

    $safe_path = htmlspecialchars($file_path);
    $safe_title = htmlspecialchars($title ?: $issue);
    $safe_problem = htmlspecialchars($problem);
    $safe_organism = htmlspecialchars($organism);

    // Start building alert HTML
    $html = '<div class="alert alert-warning alert-dismissible fade show mb-3">' . "\n";
    $html .= '  <button type="button" class="btn-close" data-bs-dismiss="alert"></button>' . "\n";
    $html .= '  <h6><i class="fa fa-exclamation-circle"></i> ' . $safe_title . '</h6>' . "\n";

    if ($safe_problem) {
        $html .= '  <p class="mb-2"><strong>Problem:</strong> ' . $safe_problem . '</p>' . "\n";
    }

    $html .= '  <p class="mb-3"><strong>Current Status:</strong></p>' . "\n";
    $html .= '  <ul class="mb-3 small">' . "\n";
    $html .= '    <li>Path: <code>' . $safe_path . '</code></li>' . "\n";
    $html .= '    <li>Type: ' . ($is_dir ? 'Directory' : 'File') . '</li>' . "\n";
    $html .= '    <li>Owner: <code>' . htmlspecialchars($owner_name) . '</code></li>' . "\n";
    $html .= '    <li>Permissions: <code>' . $perms . '</code></li>' . "\n";
    $html .= '    <li>Readable: <span class="badge ' . ($readable ? 'bg-success' : 'bg-danger') . '">' . ($readable ? '✓ Yes' : '✗ No') . '</span></li>' . "\n";
    $html .= '    <li>Writable: <span class="badge ' . ($writable ? 'bg-success' : 'bg-danger') . '">' . ($writable ? '✓ Yes' : '✗ No') . '</span></li>' . "\n";
    $html .= '    <li>Web server user: <code>' . htmlspecialchars($web_user) . '</code></li>' . "\n";
    $html .= '  </ul>' . "\n";

    if ($can_fix) {
        // Web server can fix it - offer button
        $resultId = 'fixResult-' . uniqid();
        $html .= '  <p class="mb-2"><strong>Quick Fix:</strong> Click the button below to attempt automatic fix:</p>' . "\n";
        $html .= '  <button class="btn btn-warning btn-sm" onclick=\'fixFilePermissions(event, ' . json_encode($file_path) . ', ' . json_encode($file_type) . ', ' . json_encode($organism) . ', ' . json_encode($resultId) . ');\'>' . "\n";
        $html .= '    <i class="fa fa-wrench"></i> Fix Permissions' . "\n";
        $html .= '  </button>' . "\n";
        $html .= '  <div id="' . $resultId . '" class="mt-3"></div>' . "\n";

        // Show manual instructions as alternative
        $html .= '  <p class="mb-2 mt-4"><strong>Or manually on the server:</strong></p>' . "\n";
        $html .= '  <div style="margin: 10px 0; background: #f0f0f0; padding: 10px; border-radius: 4px; border: 1px solid #ddd;">' . "\n";
        $html .= '    <code style="word-break: break-all; display: block; font-size: 0.9em;">' . "\n";
        if ($is_dir) {
            $html .= '      sudo chgrp -R ' . htmlspecialchars($web_group) . ' ' . $safe_path . '<br>' . "\n";
            $html .= '      sudo chmod -R 775 ' . $safe_path . "\n";
        } else {
            $html .= '      sudo chgrp ' . htmlspecialchars($web_group) . ' ' . $safe_path . '<br>' . "\n";
            $html .= '      sudo chmod 664 ' . $safe_path . "\n";
        }
        $html .= '    </code>' . "\n";
        $html .= '  </div>' . "\n";
    } else {
        // Web server cannot fix - show manual instructions
        $html .= '  <p class="mb-2"><strong>To Fix:</strong> Run this command on the server:</p>' . "\n";
        $html .= '  <div style="margin: 10px 0; background: #f0f0f0; padding: 10px; border-radius: 4px; border: 1px solid #ddd;">' . "\n";
        $html .= '    <code style="word-break: break-all; display: block; font-size: 0.9em;">' . "\n";
        if ($is_dir) {
            $html .= '      sudo chgrp -R ' . htmlspecialchars($web_group) . ' ' . $safe_path . '<br>' . "\n";
            $html .= '      sudo chmod -R 775 ' . $safe_path . "\n";
        } else {
            $html .= '      sudo chgrp ' . htmlspecialchars($web_group) . ' ' . $safe_path . '<br>' . "\n";
            $html .= '      sudo chmod 664 ' . $safe_path . "\n";
        }
        $html .= '    </code>' . "\n";
        $html .= '  </div>' . "\n";
    }

    $html .= '  <p class="small text-muted mb-0">After fixing permissions, refresh this page.</p>' . "\n";
    $html .= '</div>' . "\n";

    // Include permission-manager.js if the quick-fix button was rendered
    if ($can_fix) {
        $config = ConfigManager::getInstance();
        $site = $config->getString('site');
        $html .= '<script src="/' . htmlspecialchars($site) . '/js/permission-manager.js"></script>' . "\n";
    }

    return $html;
}

function getColorClassOrStyle($color) {
    $result = [
        'class' => '',
        'style' => ''
    ];

    if (empty($color)) {
        $result['class'] = 'btn-secondary';
        return $result;
    }

    // Check if it's a hex color (#RGB or #RRGGBB)
    if (preg_match('/^#([0-9a-f]{3}|[0-9a-f]{6})$/i', $color)) {
        $result['style'] = 'background-color: ' . htmlspecialchars($color) . '; border-color: ' . htmlspecialchars($color) . ';';
    } else {
        // Treat as Bootstrap class
        $result['class'] = htmlspecialchars($color);
    }

    return $result;
}

functions.comment:
/**
* Ensure directory exists with proper permissions
*/

functions.code:
function ensureDirectoryExists($directory, $owner = null, $group = null) {
    if ($owner === null) {
        $owner = getMoopOwner();
    }
    if ($group === null) {
        $webserver = getWebServerUser();
        $group = $webserver['group'];
    }
    if (is_dir($directory)) {
        return true;
    }

    if (!@mkdir($directory, 0775, true)) {
        logError('Failed to create directory', 'directory_creation', ['directory' => $directory]);
        return false;
    }

    @chown($directory, $owner);
    @chgrp($directory, $group);
    @chmod($directory, 0775);

    return true;
}

functions.comment:
/**
* Download image from Wikimedia and cache locally
*/

functions.code:
function downloadWikimediaImage($wiki_url, $cache_filename, $cache_directory = '') {
    $config = ConfigManager::getInstance();
    $site = $config->getString('site');

    if (empty($cache_directory)) {
        $images_path = $config->getPath('absolute_images_path');
        $cache_directory = $images_path . '/wikimedia';
    }

    if (!ensureDirectoryExists($cache_directory)) {
        logError('Could not create wikimedia cache directory', 'wikimedia_download', ['directory' => $cache_directory]);
        return false;
    }

    $cache_file = $cache_directory . '/' . basename($cache_filename);

    if (file_exists($cache_file)) {
        return "/$site/images/wikimedia/" . basename($cache_filename);
    }

    $image_data = moop_curl_get($wiki_url, 10, 20);

    if ($image_data === false) {
        logError('Failed to download Wikimedia image', 'wikimedia_download', ['wiki_url' => $wiki_url]);
        return false;
    }

    if (@file_put_contents($cache_file, $image_data) === false) {
        logError('Failed to write cached image', 'wikimedia_download', ['cache_file' => $cache_file]);
        return false;
    }

    @chmod($cache_file, 0664);

    return "/$site/images/wikimedia/" . basename($cache_filename);
}

functions.comment:
/**
* Get image path for group with fallback logic
*/

functions.code:
function getGroupImagePath($group_info, $absolute_images_path = '') {
    $config = ConfigManager::getInstance();
    $site = $config->getString('site');

    if (empty($group_info) || !is_array($group_info) || empty($group_info['name'])) {
        return '';
    }

    $group_name = $group_info['name'];
    $safe_group_name = basename($group_name);

    if (empty($absolute_images_path)) {
        $absolute_images_path = $config->getPath('images_path');
    }

    // 1. Check for custom group image
    $extensions = ['jpg', 'jpeg', 'png', 'gif', 'webp'];
    $custom_image_dir = "$absolute_images_path/groups/";
    foreach ($extensions as $ext) {
        $custom_image = $custom_image_dir . $safe_group_name . '.' . $ext;
        if (file_exists($custom_image)) {
            return "/$site/images/groups/" . $safe_group_name . '.' . $ext;
        }
    }

    // 2. Check for cached Wikimedia image
    $wikimedia_dir = "$absolute_images_path/wikimedia/";
    foreach ($extensions as $ext) {
        $wikimedia_image = $wikimedia_dir . $safe_group_name . '.' . $ext;
        if (file_exists($wikimedia_image)) {
            return "/$site/images/wikimedia/" . $safe_group_name . '.' . $ext;
        }
    }

    // 3. Try to download from Wikipedia if URL available
    if (!empty($group_info['wikipedia_image'])) {
        $wiki_url = $group_info['wikipedia_image'];
        if (strpos($wiki_url, 'wikimedia.org') !== false || strpos($wiki_url, 'wikipedia.org') !== false) {
            $url_path = parse_url($wiki_url, PHP_URL_PATH);
            $ext = pathinfo($url_path, PATHINFO_EXTENSION);
            if (empty($ext)) {
                $ext = 'jpg';
            }

            $cache_filename = $safe_group_name . '.' . $ext;
            $result = downloadWikimediaImage($wiki_url, $cache_filename, $wikimedia_dir);
            if ($result !== false) {
                return $result;
            }
        }
    }

    return '';
}

function logError($error_message, $context = '', $additional_info = []) {
    $config = ConfigManager::getInstance();
    $log_file = $config->getPath('error_log_file');

    $error_entry = [
        'timestamp' => date('Y-m-d H:i:s'),
        'error' => $error_message,
        'context' => $context,
        'user' => $_SESSION['username'] ?? 'anonymous',
        'page' => $_SERVER['REQUEST_URI'] ?? '',
        'ip' => $_SERVER['REMOTE_ADDR'] ?? '',
        'details' => $additional_info
    ];

    $log_line = json_encode($error_entry) . "\n";

    if ($log_file) {
        error_log($log_line, 3, $log_file);
    }
}

function getErrorLog($limit = 0) {
    $config = ConfigManager::getInstance();
    $log_file = $config->getPath('error_log_file');

    if (!$log_file || !file_exists($log_file)) {
        return [];
    }

    $lines = file($log_file, FILE_IGNORE_NEW_LINES | FILE_SKIP_EMPTY_LINES);
    if (!$lines) {
        return [];
    }

    $errors = [];
    foreach (array_reverse($lines) as $line) {
        $error = json_decode($line, true);
        if ($error) {
            $errors[] = $error;
        }
    }

    if ($limit > 0) {
        $errors = array_slice($errors, 0, $limit);
    }

    return $errors;
}

function clearErrorLog() {
    $config = ConfigManager::getInstance();
    $log_file = $config->getPath('error_log_file');

    if (!$log_file) {
        return false;
    }

    return file_put_contents($log_file, '') !== false;
}

function validateDirectoryName($name) {
    return strpos($name, '/') === false && 
           strpos($name, '..') === false &&
           $name !== '.' && 
           $name !== '..' &&
           $name !== 'organism.json';
}

function buildDirectoryResult($success, $message, $command = '') {
    return [
        'success' => $success,
        'message' => $message,
        'command' => $command
    ];
}

function validateAssemblyDirectories($dbFile, $organism_data_dir) {
    $result = [
        'valid' => true,
        'genomes' => [],
        'mismatches' => [],
        'errors' => []
    ];

    if (!file_exists($dbFile) || !is_readable($dbFile)) {
        $result['valid'] = false;
        $result['errors'][] = 'Database not readable';
        return $result;
    }

    if (!is_dir($organism_data_dir)) {
        $result['valid'] = false;
        $result['errors'][] = 'Organism directory not found';
        return $result;
    }

    try {
        $dbh = getDbConnection($dbFile);

        // Get all genome records
        $stmt = $dbh->query("SELECT genome_id, genome_name, genome_accession FROM genome ORDER BY genome_name");
        $genomes = $stmt->fetchAll(PDO::FETCH_ASSOC);

        // Get list of directories in organism folder
        $dirs = array_diff(scandir($organism_data_dir), ['.', '..']);
        $dir_names = [];
        foreach ($dirs as $dir) {
            $full_path = "$organism_data_dir/$dir";
            if (is_dir($full_path)) {
                $dir_names[] = $dir;
            }
        }

        // Get gene_set records grouped by genome_id
        $gene_sets_by_genome = [];
        try {
            $gs_stmt = $dbh->query("SELECT gene_set_id, genome_id, gene_set_name FROM gene_set ORDER BY gene_set_name");
            foreach ($gs_stmt->fetchAll(PDO::FETCH_ASSOC) as $gs) {
                $gene_sets_by_genome[$gs['genome_id']][] = $gs;
            }
        } catch (PDOException $e) {
            // gene_set table may not exist in older DBs — treat as no gene sets
        }

        // Check each genome record
        foreach ($genomes as $genome) {
            $name      = $genome['genome_name'];
            $accession = $genome['genome_accession'];
            $genome_id = $genome['genome_id'];

            // Check if either name or accession matches an assembly directory
            $found_dir = null;
            if (in_array($name, $dir_names)) {
                $found_dir = $name;
            } elseif (in_array($accession, $dir_names)) {
                $found_dir = $accession;
            }

            // Check gene_set subdirs within the assembly directory
            $gene_set_checks = [];
            if ($found_dir !== null) {
                $asm_path = "$organism_data_dir/$found_dir";
                foreach ($gene_sets_by_genome[$genome_id] ?? [] as $gs) {
                    $gs_exists = is_dir("$asm_path/{$gs['gene_set_name']}");
                    $gene_set_checks[] = [
                        'gene_set_id'   => $gs['gene_set_id'],
                        'gene_set_name' => $gs['gene_set_name'],
                        'dir_exists'    => $gs_exists,
                    ];
                    if (!$gs_exists) {
                        $result['valid'] = false;
                        $result['mismatches'][] = [
                            'type'           => 'missing_gene_set_directory',
                            'genome_name'    => $name,
                            'genome_accession' => $accession,
                            'assembly_dir'   => $found_dir,
                            'gene_set_name'  => $gs['gene_set_name'],
                            'message'        => "No directory found for gene_set '{$gs['gene_set_name']}' inside assembly '$found_dir'"
                        ];
                    }
                }

                // Reverse direction: gene_set directories on disk with no matching DB
                // row. Happens when a gene_set is dropped from the database (DB rebuilt
                // elsewhere, rows deleted) but its directory was never removed here — the
                // DB-driven checks above can't see this since they only walk DB rows.
                $known_gene_set_names = array_column($gene_sets_by_genome[$genome_id] ?? [], 'gene_set_name');
                foreach (glob("$asm_path/*", GLOB_ONLYDIR) ?: [] as $gs_dir) {
                    $gs_name = basename($gs_dir);
                    if (in_array($gs_name, $known_gene_set_names, true)) continue;
                    if (!file_exists("$gs_dir/" . genes_gff_filename())) continue; // not a real gene_set dir
                    $result['valid'] = false;
                    $result['mismatches'][] = [
                        'type'             => 'orphaned_gene_set_directory',
                        'genome_name'      => $name,
                        'genome_accession' => $accession,
                        'assembly_dir'     => $found_dir,
                        'gene_set_name'    => $gs_name,
                        'message'          => "Directory '{$gs_name}' exists on disk but has no matching gene_set row in the database — likely deleted upstream",
                    ];
                }
            }

            $result['genomes'][] = [
                'genome_id'        => $genome_id,
                'genome_name'      => $name,
                'genome_accession' => $accession,
                'directory_found'  => $found_dir,
                'exists'           => $found_dir !== null,
                'gene_set_checks'  => $gene_set_checks,
            ];

            if ($found_dir === null) {
                $result['valid'] = false;
                $result['mismatches'][] = [
                    'type'             => 'missing_directory',
                    'genome_name'      => $name,
                    'genome_accession' => $accession,
                    'message'          => "No directory found matching genome_name '$name' or genome_accession '$accession'"
                ];
            } elseif ($found_dir !== $name && $found_dir !== $accession) {
                $result['mismatches'][] = [
                    'type'             => 'name_mismatch',
                    'genome_name'      => $name,
                    'genome_accession' => $accession,
                    'found_directory'  => $found_dir,
                    'message'          => "Directory '$found_dir' found, but doesn't match genome_name '$name' or genome_accession '$accession'"
                ];
            }
        }

        // Reverse direction at the ASSEMBLY level: directories on disk that are shaped
        // like an assembly (they carry a genome.json) but match no genome row by name or
        // accession. The DB-driven loop above only walks rows outward to disk, so a whole
        // assembly dir dropped from the DB (rebuilt/removed upstream, or superseded by a
        // rename) but left on disk stays invisible to every other check. genome.json is
        // the marker for "this dir was meant to be an assembly" — same idea as requiring
        // a genes gff to treat a subdir as a real gene_set above.
        $known_assembly_dirs = [];
        foreach ($genomes as $genome) {
            if ($genome['genome_name'] !== '')      $known_assembly_dirs[$genome['genome_name']] = true;
            if ($genome['genome_accession'] !== '') $known_assembly_dirs[$genome['genome_accession']] = true;
        }
        foreach ($dir_names as $dir) {
            if (isset($known_assembly_dirs[$dir])) continue;
            if (!file_exists("$organism_data_dir/$dir/genome.json")) continue; // not an assembly dir
            $result['valid'] = false;
            $result['mismatches'][] = [
                'type'         => 'orphaned_assembly_directory',
                'assembly_dir' => $dir,
                'message'      => "Directory '$dir' exists on disk with a genome.json but has no matching genome row in the database — likely a stale leftover from a rename or reload",
            ];
        }

        $dbh = null;
    } catch (PDOException $e) {
        $result['valid'] = false;
        $result['errors'][] = 'Database query failed: ' . $e->getMessage();
    }

    return $result;
}

function validateAssemblyFastaFiles($organism_dir, $sequence_types) {
    $result = [
        'assemblies' => [],
        'missing_files' => []
    ];

    if (!is_dir($organism_dir)) {
        return $result;
    }

    // Get all directories in organism folder
    $dirs = array_diff(scandir($organism_dir), ['.', '..']);

    foreach ($dirs as $dir) {
        $full_path = "$organism_dir/$dir";
        if (!is_dir($full_path)) {
            continue;
        }

        $assembly_info = [
            'name' => $dir,
            'fasta_files' => [],
            'missing_patterns' => []
        ];

        // Collect gene_set subdirs within this assembly dir
        $gene_set_dirs = array_values(array_filter(
            array_diff(scandir($full_path), ['.', '..']),
            fn($f) => is_dir("$full_path/$f")
        ));

        // Check for each sequence type pattern — assembly-level first, then gene_set subdirs
        foreach ($sequence_types as $type => $config) {
            $pattern = $config['pattern'];
            $found_file = null;

            // Check directly in the assembly dir (e.g. genome.fa lives here)
            $direct = glob("$full_path/*$pattern");
            if (!empty($direct)) {
                $found_file = basename($direct[0]);
            }

            // If not found at assembly level, check inside each gene_set subdir
            if ($found_file === null) {
                foreach ($gene_set_dirs as $gs) {
                    $files = glob("$full_path/$gs/*$pattern");
                    if (!empty($files)) {
                        $found_file = basename($files[0]);
                        break;
                    }
                }
            }

            if ($found_file !== null) {
                $assembly_info['fasta_files'][$type] = [
                    'found' => true,
                    'pattern' => $pattern,
                    'file' => $found_file
                ];
            } else {
                $assembly_info['fasta_files'][$type] = [
                    'found' => false,
                    'pattern' => $pattern
                ];
                $assembly_info['missing_patterns'][] = $pattern;
            }
        }

        $result['assemblies'][$dir] = $assembly_info;

        if (!empty($assembly_info['missing_patterns'])) {
            $result['missing_files'][$dir] = $assembly_info['missing_patterns'];
        }
    }

    return $result;
}

function renameAssemblyDirectory($organism_dir, $old_name, $new_name) {
    if (!is_dir($organism_dir)) {
        return buildDirectoryResult(false, 'Organism directory not found');
    }

    // Validate both names for security
    if (!validateDirectoryName($old_name) || !validateDirectoryName($new_name)) {
        return buildDirectoryResult(false, 'Invalid directory name (contains path separators)');
    }

    $old_path = "$organism_dir/$old_name";
    $new_path = "$organism_dir/$new_name";

    // Validate old directory exists
    if (!is_dir($old_path)) {
        return buildDirectoryResult(false, "Directory '$old_name' not found");
    }

    // Check new name doesn't already exist
    if (is_dir($new_path) || file_exists($new_path)) {
        return buildDirectoryResult(false, "Directory '$new_name' already exists");
    }

    // Build command for admin to run if automatic rename fails
    $command = "cd " . escapeshellarg($organism_dir) . " && mv " . escapeshellarg($old_name) . " " . escapeshellarg($new_name);

    // Try to rename
    if (@rename($old_path, $new_path)) {
        return buildDirectoryResult(true, "Successfully renamed '$old_name' to '$new_name'", $command);
    } else {
        return buildDirectoryResult(false, 'Web server lacks permission to rename directory.', $command);
    }
}

function renameGeneSetDirectory($organism_dir, $assembly, $old_name, $new_name) {
    if (!validateDirectoryName($assembly) || !validateDirectoryName($old_name) || !validateDirectoryName($new_name)) {
        return buildDirectoryResult(false, 'Invalid directory name (contains path separators)');
    }

    $assembly_path = "$organism_dir/$assembly";

    if (!is_dir($assembly_path)) {
        return buildDirectoryResult(false, "Assembly directory '$assembly' not found");
    }

    $old_path = "$assembly_path/$old_name";
    $new_path = "$assembly_path/$new_name";

    if (!is_dir($old_path)) {
        return buildDirectoryResult(false, "Gene set directory '$old_name' not found in '$assembly'");
    }

    if (is_dir($new_path) || file_exists($new_path)) {
        return buildDirectoryResult(false, "Directory '$new_name' already exists in '$assembly'");
    }

    $command = "cd " . escapeshellarg($assembly_path) . " && mv " . escapeshellarg($old_name) . " " . escapeshellarg($new_name);

    if (@rename($old_path, $new_path)) {
        return buildDirectoryResult(true, "Successfully renamed '$old_name' to '$new_name'", $command);
    } else {
        return buildDirectoryResult(false, 'Web server lacks permission to rename directory.', $command);
    }
}

function deleteAssemblyDirectory($organism_dir, $dir_name) {
    if (!is_dir($organism_dir)) {
        return buildDirectoryResult(false, 'Organism directory not found');
    }

    // Validate directory name for security
    if (!validateDirectoryName($dir_name)) {
        return buildDirectoryResult(false, 'Invalid directory name (security check failed)');
    }

    $dir_path = "$organism_dir/$dir_name";

    // Validate directory exists
    if (!is_dir($dir_path)) {
        return buildDirectoryResult(false, "Directory '$dir_name' not found");
    }

    // Build command for admin to run if automatic delete fails
    $command = "rm -rf " . escapeshellarg($dir_path);

    // Try to delete recursively
    if (rrmdir($dir_path)) {
        return buildDirectoryResult(true, "Successfully deleted directory '$dir_name'", $command);
    } else {
        return buildDirectoryResult(false, 'Web server lacks permission to delete directory.', $command);
    }
}

function rrmdir($dir) {
    if (!is_dir($dir)) {
        return false;
    }

    $items = scandir($dir);
    foreach ($items as $item) {
        if ($item === '.' || $item === '..') {
            continue;
        }
        $path = $dir . '/' . $item;
        if (is_dir($path)) {
            if (!rrmdir($path)) {
                return false;
            }
        } else {
            if (!@unlink($path)) {
                return false;
            }
        }
    }

    return @rmdir($dir);
}

function getFileWriteError($filepath) {
    if (!file_exists($filepath) || is_writable($filepath)) {
        return null;
    }

    $webserver = getWebServerUser();
    $web_user = $webserver['user'];
    $web_group = $webserver['group'];

    $current_owner = function_exists('posix_getpwuid') ? posix_getpwuid(fileowner($filepath))['name'] ?? 'unknown' : 'unknown';
    $current_group = function_exists('posix_getgrgid') ? posix_getgrgid(filegroup($filepath))['name'] ?? 'unknown' : 'unknown';
    $perms_full = substr(sprintf('%o', fileperms($filepath)), -4);
    $current_perms = ltrim($perms_full, '0') ?: '0';

    // Command keeps original owner but changes group to webserver and sets perms to 664
    $fix_command = "sudo chgrp " . escapeshellarg($web_group) . " " . escapeshellarg($filepath) . " && sudo chmod 664 " . escapeshellarg($filepath);

    return [
        'owner' => $current_owner,
        'group' => $current_group,
        'perms' => $current_perms,
        'web_user' => $web_user,
        'web_group' => $web_group,
        'command' => $fix_command,
        'file' => $filepath
    ];
}

function getDirectoryError($dirpath) {
    if (is_dir($dirpath) && is_writable($dirpath)) {
        return null;
    }

    $webserver = getWebServerUser();
    $web_group = $webserver['group'];

    $moop_owner = getMoopOwner();

    // Detect if sudo is needed
    $current_uid = function_exists('posix_getuid') ? posix_getuid() : null;
    $need_sudo = false;

    if ($current_uid !== null && $current_uid !== 0) {
        // Not running as root, check if we're the moop owner
        $current_user = function_exists('posix_getpwuid') ? posix_getpwuid($current_uid)['name'] ?? null : null;
        if ($current_user !== $moop_owner) {
            $need_sudo = true;
        }
    }

    // Helper function to add sudo if needed
    $cmd_prefix = $need_sudo ? 'sudo ' : '';

    if (!is_dir($dirpath)) {
        // Directory doesn't exist
        return [
            'type' => 'missing',
            'dir' => $dirpath,
            'owner' => $moop_owner,
            'group' => $web_group,
            'need_sudo' => $need_sudo,
            'commands' => [
                "{$cmd_prefix}mkdir -p " . escapeshellarg($dirpath),
                "{$cmd_prefix}chown {$moop_owner}:{$web_group} " . escapeshellarg($dirpath),
                "{$cmd_prefix}chmod 775 " . escapeshellarg($dirpath)
            ]
        ];
    }

    // Directory exists but not writable
    $current_owner = function_exists('posix_getpwuid') ? posix_getpwuid(fileowner($dirpath))['name'] ?? 'unknown' : 'unknown';
    $perms_full = substr(sprintf('%o', fileperms($dirpath)), -4);
    $current_perms = ltrim($perms_full, '0') ?: '0';

    return [
        'type' => 'not_writable',
        'dir' => $dirpath,
        'owner' => $current_owner,
        'perms' => $current_perms,
        'target_owner' => $moop_owner,
        'target_group' => $web_group,
        'need_sudo' => $need_sudo,
        'commands' => [
            "{$cmd_prefix}chown {$moop_owner}:{$web_group} " . escapeshellarg($dirpath),
            "{$cmd_prefix}chmod 775 " . escapeshellarg($dirpath)
        ]
    ];
}

function getRegistryLastUpdate($htmlFile, $mdFile, $scanDirBase = null) {
    $lastUpdate = 'Never';
    $lastUpdateTime = 0;
    $isStale = false;

    // Try to get from HTML file first (has "Generated:" timestamp)
    if (file_exists($htmlFile) && is_readable($htmlFile)) {
        $content = file_get_contents($htmlFile);
        // Look for "Generated: YYYY-MM-DD HH:MM:SS" in the HTML
        if (preg_match('/Generated:\s*(\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2})/', $content, $matches)) {
            $lastUpdate = $matches[1];
            $lastUpdateTime = strtotime($lastUpdate);
        }
    }

    // Fallback to file modification time
    if ($lastUpdateTime === 0) {
        if (file_exists($htmlFile)) {
            $lastUpdateTime = filemtime($htmlFile);
            $lastUpdate = date('Y-m-d H:i:s', $lastUpdateTime);
        } elseif (file_exists($mdFile)) {
            $lastUpdateTime = filemtime($mdFile);
            $lastUpdate = date('Y-m-d H:i:s', $lastUpdateTime);
        }
    }

    // Check if any PHP files are newer than the registry (only if registry exists)
    if ($lastUpdateTime > 0) {
        if ($scanDirBase === null) {
            // Default to parent directory of lib/
            $scanDirBase = dirname(dirname(__FILE__));
        }

        $scanDirs = [
            $scanDirBase . '/lib',
            $scanDirBase . '/tools',
            $scanDirBase . '/admin',
            $scanDirBase
        ];

        foreach ($scanDirs as $dir) {
            if (!is_dir($dir)) continue;

            try {
                $files = new RecursiveIteratorIterator(
                    new RecursiveDirectoryIterator($dir),
                    RecursiveIteratorIterator::LEAVES_ONLY
                );

                foreach ($files as $file) {
                    if (!$file->isFile() || $file->getExtension() !== 'php') continue;

                    $filePath = $file->getRealPath();

                    // Skip excluded files and directories
                    $excludePatterns = ['docs/', 'logs/', 'notes/', 'not_used/', '.git/', 'generate_registry'];
                    $skip = false;
                    foreach ($excludePatterns as $pattern) {
                        if (strpos($filePath, $pattern) !== false) {
                            $skip = true;
                            break;
                        }
                    }
                    if ($skip) continue;

                    $fileTime = filemtime($filePath);
                    if ($fileTime > $lastUpdateTime) {
                        $isStale = true;
                        break 2;
                    }
                }
            } catch (Exception $e) {
                error_log("Error checking PHP file timestamps: " . $e->getMessage());
            }
        }
    }

    return [
        'timestamp' => $lastUpdate,
        'isStale' => $isStale,
        'status' => $isStale ? 'You should update' : 'Up to date'
    ];
}

function getNewestSqliteModTime($organisms_path) {
    if (!is_dir($organisms_path)) {
        return null;
    }

    $newest_time = 0;
    $found = false;

    try {
        // Scan organism directories one level deep
        $organisms = scandir($organisms_path);
        foreach ($organisms as $organism) {
            if ($organism === '.' || $organism === '..') {
                continue;
            }

            $organism_dir = $organisms_path . '/' . $organism;
            if (!is_dir($organism_dir)) {
                continue;
            }

            $sqlite_file = $organism_dir . '/organism.sqlite';
            if (file_exists($sqlite_file)) {
                $mtime = filemtime($sqlite_file);
                if ($mtime > $newest_time) {
                    $newest_time = $mtime;
                    $found = true;
                }
            }
        }
    } catch (Exception $e) {
        error_log("Error scanning SQLite files: " . $e->getMessage());
        return null;
    }

    if (!$found) {
        return null;
    }

    return [
        'unix_time' => $newest_time,
        'timestamp' => date('Y-m-d H:i:s', $newest_time),
        'iso8601' => date('c', $newest_time)
    ];
}

function loadJsonFile($path, $default = []) {
    if (!file_exists($path)) {
        return $default;
    }

    $json_content = file_get_contents($path);
    if ($json_content === false) {
        return $default;
    }

    $data = json_decode($json_content, true);
    return $data !== null ? $data : $default;
}

function loadJsonFileRequired($path, $errorMsg = '', $exitOnError = false) {
    if (!file_exists($path)) {
        if ($errorMsg) {
            error_log($errorMsg);
        }
        if ($exitOnError) {
            header("HTTP/1.1 500 Internal Server Error");
            exit("Required data file not found");
        }
        return [];
    }

    $json_content = file_get_contents($path);
    if ($json_content === false) {
        $msg = $errorMsg ?: "Failed to read file: $path";
        error_log($msg);
        if ($exitOnError) {
            header("HTTP/1.1 500 Internal Server Error");
            exit("Failed to read required data");
        }
        return [];
    }

    $data = json_decode($json_content, true);
    if ($data === null) {
        $msg = $errorMsg ?: "Invalid JSON in file: $path";
        error_log($msg);
        if ($exitOnError) {
            header("HTTP/1.1 500 Internal Server Error");
            exit("Invalid data format");
        }
        return [];
    }

    return $data;
}

function loadAndMergeJson($file_path, $new_data = []) {
    // If file doesn't exist, just return new data
    if (!file_exists($file_path)) {
        return $new_data;
    }

    // Load existing data
    $existing = loadJsonFile($file_path);

    if (!is_array($existing)) {
        return $new_data;
    }

    // Handle wrapped JSON (extra outer braces)
    if (!isset($existing['genus']) && !isset($existing['common_name'])) {
        $keys = array_keys($existing);
        if (count($keys) > 0 && is_array($existing[$keys[0]])) {
            $existing = $existing[$keys[0]];
        }
    }

    // Merge: existing fields are preserved, new data overwrites matching keys
    return array_merge($existing, $new_data);
}

function decodeJsonString($json_string, $as_array = true) {
    if (empty($json_string)) {
        return $as_array ? [] : null;
    }

    $decoded = json_decode($json_string, $as_array);

    // Validate it decoded properly
    if ($decoded === null && json_last_error() !== JSON_ERROR_NONE) {
        error_log("JSON decode error: " . json_last_error_msg());
        return $as_array ? [] : null;
    }

    return $decoded;
}

function saveJsonFile($path, $data) {
    return file_put_contents($path, json_encode($data, JSON_PRETTY_PRINT));
}

function getAnnotationTypeMapping($annotation_config) {
    $mapping = [];

    if (!isset($annotation_config['annotation_types'])) {
        return $mapping;
    }

    foreach ($annotation_config['annotation_types'] as $canonical_name => $config) {
        // Map the canonical name to itself
        $mapping[$canonical_name] = $canonical_name;

        // Map each synonym to this canonical name
        if (isset($config['synonyms']) && is_array($config['synonyms'])) {
            foreach ($config['synonyms'] as $synonym) {
                $mapping[$synonym] = $canonical_name;
            }
        }
    }

    return $mapping;
}

function syncAnnotationTypes($annotation_config, $db_types) {
    if (!isset($annotation_config['annotation_types'])) {
        $annotation_config['annotation_types'] = [];
    }

    // Get current mapping (canonical + synonyms)
    $mapping = getAnnotationTypeMapping($annotation_config);

    // Mark all existing entries as not in database initially
    foreach ($annotation_config['annotation_types'] as &$config) {
        $config['in_database'] = false;
        $config['annotation_count'] = 0;
        $config['feature_count'] = 0;
    }
    unset($config);

    // Check which DB types are covered by existing config
    $mapped_db_types = [];
    foreach ($db_types as $db_type => $counts) {
        if (isset($mapping[$db_type])) {
            // This DB type maps to an existing config entry
            $canonical = $mapping[$db_type];
            $annotation_config['annotation_types'][$canonical]['in_database'] = true;
            $annotation_config['annotation_types'][$canonical]['annotation_count'] += $counts['annotation_count'];
            $annotation_config['annotation_types'][$canonical]['feature_count'] += $counts['feature_count'];
            $mapped_db_types[$db_type] = true;
        }
    }

    // Add unmapped DB types as new entries
    $next_order = 1;
    if (!empty($annotation_config['annotation_types'])) {
        $orders = array_map(function($c) { return $c['order'] ?? 0; }, 
                          $annotation_config['annotation_types']);
        $next_order = max($orders) + 1;
    }

    foreach ($db_types as $db_type => $counts) {
        if (!isset($mapped_db_types[$db_type])) {
            // New type not in config - add it
            $annotation_config['annotation_types'][$db_type] = [
                'display_name' => $db_type,
                'display_label' => $db_type,
                'color' => 'secondary',
                'order' => $next_order,
                'description' => '',
                'enabled' => true,
                'synonyms' => [],
                'in_database' => true,
                'annotation_count' => $counts['annotation_count'],
                'feature_count' => $counts['feature_count'],
                'new' => true
            ];
            $next_order++;
        }
    }

    return $annotation_config;
}

function consolidateSynonym(&$annotation_config, $canonical_name, $synonym_name) {
    if (!isset($annotation_config['annotation_types'][$canonical_name])) {
        return false;
    }

    if (!isset($annotation_config['annotation_types'][$synonym_name])) {
        return false;
    }

    // Add synonym entry to synonyms array
    if (!isset($annotation_config['annotation_types'][$canonical_name]['synonyms'])) {
        $annotation_config['annotation_types'][$canonical_name]['synonyms'] = [];
    }

    if (!in_array($synonym_name, $annotation_config['annotation_types'][$canonical_name]['synonyms'])) {
        $annotation_config['annotation_types'][$canonical_name]['synonyms'][] = $synonym_name;
    }

    // Combine counts
    $synonym_annotation_count = $annotation_config['annotation_types'][$synonym_name]['annotation_count'] ?? 0;
    $synonym_feature_count = $annotation_config['annotation_types'][$synonym_name]['feature_count'] ?? 0;

    if ($synonym_annotation_count > 0) {
        $annotation_config['annotation_types'][$canonical_name]['annotation_count'] = 
            ($annotation_config['annotation_types'][$canonical_name]['annotation_count'] ?? 0) + $synonym_annotation_count;
    }

    if ($synonym_feature_count > 0) {
        $annotation_config['annotation_types'][$canonical_name]['feature_count'] = 
            ($annotation_config['annotation_types'][$canonical_name]['feature_count'] ?? 0) + $synonym_feature_count;
    }

    // Mark canonical as in database if synonym was
    if ($annotation_config['annotation_types'][$synonym_name]['in_database'] ?? false) {
        $annotation_config['annotation_types'][$canonical_name]['in_database'] = true;
    }

    // Remove the synonym entry
    unset($annotation_config['annotation_types'][$synonym_name]);

    return true;
}

function getAnnotationDisplayLabel($db_annotation_type, $annotation_config) {
    if (!isset($annotation_config['annotation_types'])) {
        return $db_annotation_type;
    }

    // Get mapping
    $mapping = getAnnotationTypeMapping($annotation_config);

    // Find canonical name
    if (isset($mapping[$db_annotation_type])) {
        $canonical = $mapping[$db_annotation_type];

        // Get the configured display label for this canonical entry
        if (isset($annotation_config['annotation_types'][$canonical]['display_label'])) {
            return $annotation_config['annotation_types'][$canonical]['display_label'];
        }

        // Fallback to display_name
        if (isset($annotation_config['annotation_types'][$canonical]['display_name'])) {
            return $annotation_config['annotation_types'][$canonical]['display_name'];
        }

        return $canonical;
    }

    return $db_annotation_type;
}

function shouldUpdateAnnotationCounts($annotation_config, $newest_mod_info) {
    // If no SQLite files found, no need to update
    if ($newest_mod_info === null) {
        return false;
    }

    // If no stored modification time, update is needed
    if (!isset($annotation_config['sqlite_mod_time'])) {
        return true;
    }

    // If modification time changed, update is needed
    if ($annotation_config['sqlite_mod_time'] !== $newest_mod_info['unix_time']) {
        return true;
    }

    // Check if any annotation types are missing counts or have empty/zero values
    if (isset($annotation_config['annotation_types'])) {
        foreach ($annotation_config['annotation_types'] as $type_config) {
            // Check if counts don't exist or are empty/zero
            if (!isset($type_config['annotation_count']) || $type_config['annotation_count'] === '' || $type_config['annotation_count'] === null) {
                return true;
            }
            if (!isset($type_config['feature_count']) || $type_config['feature_count'] === '' || $type_config['feature_count'] === null) {
                return true;
            }
        }
    }

    return false;
}

function get_login_attempts_file() {
    $config   = ConfigManager::getInstance();
    $log_file = $config->getPath('error_log_file');          // e.g. /var/www/html/moop/logs/error.log
    $log_dir  = $log_file ? dirname($log_file) : sys_get_temp_dir();
    return $log_dir . '/' . LOGIN_ATTEMPTS_FILE_NAME;
}

function load_login_attempts() {
    $file = get_login_attempts_file();
    if (!file_exists($file)) {
        return [];
    }
    $data = @json_decode(file_get_contents($file), true);
    return is_array($data) ? $data : [];
}

function save_login_attempts(array $attempts) {
    $now  = time();
    $file = get_login_attempts_file();

    // Remove records that have fully expired (outside lockout window)
    foreach ($attempts as $key => $record) {
        if (($now - ($record['last_attempt'] ?? 0)) > LOCKOUT_WINDOW) {
            unset($attempts[$key]);
        }
    }

    @file_put_contents($file, json_encode($attempts, JSON_PRETTY_PRINT), LOCK_EX);
}

function get_attempt_keys($username, $ip) {
    return [
        'username_key' => 'user:' . strtolower(trim($username)),
        'ip_key'       => 'ip:'   . $ip,
    ];
}

function check_login_lockout($username, $ip) {
    $attempts = load_login_attempts();
    $keys     = get_attempt_keys($username, $ip);
    $now      = time();
    $result   = ['locked' => false, 'delayed' => false, 'message' => '', 'remaining_seconds' => 0];

    foreach ([$keys['username_key'], $keys['ip_key']] as $key) {
        $record = $attempts[$key] ?? null;
        if (!$record) {
            continue;
        }

        $count       = (int)($record['count'] ?? 0);
        $last        = (int)($record['last_attempt'] ?? 0);
        $elapsed     = $now - $last;

        // Expired window - treat as clean slate
        if ($elapsed > LOCKOUT_WINDOW) {
            continue;
        }

        if ($count >= LOCKOUT_THRESHOLD) {
            $remaining = LOCKOUT_WINDOW - $elapsed;
            $minutes   = (int)ceil($remaining / 60);
            $result['locked']            = true;
            $result['remaining_seconds'] = $remaining;
            $result['message']           = "Too many failed login attempts. Please try again in {$minutes} minute" . ($minutes === 1 ? '' : 's') . '.';
            return $result;
        }

        if ($count >= DELAY_THRESHOLD) {
            sleep(LOCKOUT_DELAY_SECONDS);
            $result['delayed'] = true;
        }
    }

    return $result;
}

function record_login_failure($username, $ip) {
    $attempts = load_login_attempts();
    $keys     = get_attempt_keys($username, $ip);
    $now      = time();

    foreach ([$keys['username_key'], $keys['ip_key']] as $key) {
        $record = $attempts[$key] ?? ['count' => 0, 'last_attempt' => $now];

        // Reset count if the window has expired
        if (($now - (int)$record['last_attempt']) > LOCKOUT_WINDOW) {
            $record['count'] = 0;
        }

        $record['count']++;
        $record['last_attempt'] = $now;
        $attempts[$key]         = $record;
    }

    save_login_attempts($attempts);

    // Log repeated failures so admins can see patterns in server logs
    $count = $attempts[$keys['username_key']]['count'] ?? 0;
    if ($count >= DELAY_THRESHOLD) {
        error_log("MOOP login: {$count} failed attempt(s) for username '" . htmlspecialchars($username, ENT_QUOTES) . "' from IP {$ip}");
    }
}

function reset_login_failures($username, $ip) {
    $attempts = load_login_attempts();
    $keys     = get_attempt_keys($username, $ip);

    unset($attempts[$keys['username_key']], $attempts[$keys['ip_key']]);

    save_login_attempts($attempts);
}

function getWebServerUser() {
    $user = 'www-data';
    $group = 'www-data';

    // Try to get the actual user running this process
    if (function_exists('posix_getuid')) {
        $uid = posix_getuid();
        $pwinfo = posix_getpwuid($uid);
        if ($pwinfo !== false) {
            $user = $pwinfo['name'];
        }
        $gid = posix_getgid();
        $grinfo = posix_getgrgid($gid);
        if ($grinfo !== false) {
            $group = $grinfo['name'];
        }
    } else {
        // Fallback without posix: parse `id` command output
        $id_output = [];
        @exec("id 2>/dev/null", $id_output);
        if (!empty($id_output[0])) {
            if (preg_match('/uid=\d+\(([^)]+)\)/', $id_output[0], $m)) {
                $user = $m[1];
            }
            if (preg_match('/gid=\d+\(([^)]+)\)/', $id_output[0], $m)) {
                $group = $m[1];
            }
        }
    }

    return ['user' => $user, 'group' => $group];
}

function getMoopOwner() {
    // Try to get owner from the moop root directory
    $moop_root = realpath(__DIR__ . '/..');
    if ($moop_root !== false && function_exists('posix_getpwuid')) {
        $stat = @stat($moop_root);
        if ($stat) {
            $pwd = posix_getpwuid($stat['uid']);
            if ($pwd) {
                return $pwd['name'];
            }
        }
    }

    // Fallback: try to get owner via shell stat command
    if ($moop_root !== false) {
        $output = [];
        @exec("stat -c '%U' " . escapeshellarg($moop_root) . " 2>/dev/null", $output);
        if (!empty($output[0]) && $output[0] !== 'UNKNOWN') {
            return $output[0];
        }
    }

    // Last resort: current process user
    if (function_exists('posix_getpwuid') && function_exists('posix_getuid')) {
        $pwd = posix_getpwuid(posix_getuid());
        if ($pwd) {
            return $pwd['name'];
        }
    }

    return 'root';
}

function fixDatabasePermissions($dbFile) {
    $result = [
        'success' => false,
        'message' => '',
        'command' => ''
    ];

    if (!file_exists($dbFile)) {
        $result['message'] = 'Database file not found';
        return $result;
    }

    if (!is_file($dbFile)) {
        $result['message'] = 'Path is not a file';
        return $result;
    }

    // Get web server user
    $webserver = getWebServerUser();
    $web_user = $webserver['user'];
    $web_group = $webserver['group'];

    // Get file info for reporting
    $file_owner = function_exists('posix_getpwuid') ? posix_getpwuid(fileowner($dbFile))['name'] : 'unknown';
    $file_group = function_exists('posix_getgrgid') ? posix_getgrgid(filegroup($dbFile))['name'] : 'unknown';
    $current_perms = substr(sprintf('%o', fileperms($dbFile)), -4);

    // Build command for admin to run if automatic fix fails
    $result['command'] = "sudo chmod 644 " . escapeshellarg($dbFile) . " && sudo chown " . escapeshellarg("$web_user:$web_group") . " " . escapeshellarg($dbFile);

    // Try to fix permissions
    try {
        // Try chmod to make readable (644 = rw-r--r--)
        $chmod_result = @chmod($dbFile, 0644);

        if (!$chmod_result) {
            $result['message'] = 'Web server lacks permission to change file permissions.';
            return $result;
        }

        // Try to change ownership to web server user (may fail if not root)
        @chown($dbFile, $web_user);
        @chgrp($dbFile, $web_group);

        // Verify it worked
        if (is_readable($dbFile)) {
            $result['success'] = true;
            $result['message'] = 'Permissions fixed successfully! Database is now readable.';
        } else {
            $result['message'] = 'Permissions were modified but file still not readable.';
        }

    } catch (Exception $e) {
        $result['message'] = 'Error: ' . $e->getMessage();
    }

    return $result;
}

function fixFilePermissions($file_path, $file_type = 'file') {
    $result = [
        'success' => false,
        'message' => '',
        'command' => ''
    ];

    // Validate input
    if (empty($file_path) || !file_exists($file_path)) {
        $result['message'] = 'File or directory not found';
        return $result;
    }

    $is_dir = is_dir($file_path);

    // Get web server user info
    $webserver = getWebServerUser();
    $web_user = $webserver['user'];
    $web_group = $webserver['group'];

    try {
        if ($is_dir) {
            // For directories: chmod 755 (rwxr-xr-x)
            $chmod_result = @chmod($file_path, 0755);

            if (!$chmod_result) {
                $result['message'] = 'Web server lacks permission to change directory permissions.';
                return $result;
            }

            // Verify it worked
            if (is_readable($file_path) && is_writable($file_path)) {
                $result['success'] = true;
                $result['message'] = 'Directory permissions fixed successfully!';
            } else {
                $result['message'] = 'Permissions were modified but directory still has issues.';
            }
        } else {
            // For files: chmod 664 (rw-rw-r--)
            $chmod_result = @chmod($file_path, 0664);

            if ($chmod_result) {
                // chmod worked
                if (is_readable($file_path) && is_writable($file_path)) {
                    $result['success'] = true;
                    $result['message'] = 'File permissions fixed successfully!';
                } else {
                    $result['message'] = 'Permissions were modified but file still has issues.';
                }
            } else {
                // chmod failed - try to recreate the file if parent is writable
                $parent_dir = dirname($file_path);
                if (is_writable($parent_dir)) {
                    // Read current content
                    $content = @file_get_contents($file_path);
                    if ($content === false) {
                        $result['message'] = 'Cannot read file content for recreation.';
                        return $result;
                    }

                    // Delete and recreate with new permissions
                    @unlink($file_path);
                    $write_result = @file_put_contents($file_path, $content);

                    if ($write_result === false) {
                        $result['message'] = 'Failed to recreate file with new permissions.';
                        return $result;
                    }

                    // chmod the newly created file
                    @chmod($file_path, 0664);

                    if (is_readable($file_path) && is_writable($file_path)) {
                        $result['success'] = true;
                        $result['message'] = 'File permissions fixed successfully!';
                    } else {
                        $result['message'] = 'File recreated but permissions still have issues.';
                    }
                } else {
                    $result['message'] = 'Web server lacks permission to change file permissions.';
                }
            }
        }
    } catch (Exception $e) {
        $result['message'] = 'Error: ' . $e->getMessage();
    }

    return $result;
}

